  1→"use client";
  2→
  3→import { useEffect, useMemo, useRef, useState } from "react";
  4→import { Bot, Loader2, Send, Sparkles, User, X } from "lucide-react";
  5→import { Button } from "@/components/ui/button";
  6→import { Input } from "@/components/ui/input";
  7→import { ScrollArea } from "@/components/ui/scroll-area";
  8→import { cn } from "@/lib/utils";
  9→
 10→interface ToolCall {
 11→  name: string;
 12→  args: any;
 13→  result?: any;
 14→}
 15→
 16→interface Message {
 17→  role: "user" | "assistant";
 18→  content: string;
 19→  toolCalls?: ToolCall[];
 20→  timestamp: Date;
 21→}
 22→
 23→interface AIChatProps {
 24→  embedded?: boolean;
 25→}
 26→
 27→const QUICK_ACTIONS = [
 28→  { label: "Scrape all", prompt: "Scrape all platforms and summarize new jobs." },
 29→  { label: "Pipeline", prompt: "Give me current pipeline stats in 5 bullets." },
 30→  { label: "Top jobs", prompt: "Show 5 strongest IT opdrachten this week." },
 31→];
 32→
 33→export function AIChat({ embedded = false }: AIChatProps) {
 34→  const [isOpen, setIsOpen] = useState(embedded);
 35→  const [input, setInput] = useState("");
 36→  const [isLoading, setIsLoading] = useState(false);
 37→  const [error, setError] = useState<string | null>(null);
 38→  const [messages, setMessages] = useState<Message[]>([
 39→    {
 40→      role: "assistant",
 41→      content: "I can run scrapers, summarize market activity, and help triage candidates. What do you need right now?",
 42→      timestamp: new Date(),
 43→    },
 44→  ]);
 45→  const endRef = useRef<HTMLDivElement>(null);
 46→
 47→  useEffect(() => {
 48→    if (embedded) setIsOpen(true);
 49→  }, [embedded]);
 50→
 51→  useEffect(() => {
 52→    endRef.current?.scrollIntoView({ behavior: "smooth" });
 53→  }, [messages, isLoading]);
 54→
 55→  useEffect(() => {
 56→    if (embedded) return;
 57→    const onKeyDown = (e: KeyboardEvent) => {
 58→      if ((e.metaKey || e.ctrlKey) && e.key.toLowerCase() === "k") {
 59→        e.preventDefault();
 60→        setIsOpen((prev) => !prev);
 61→      }
 62→    };
 63→    window.addEventListener("keydown", onKeyDown);
 64→    return () => window.removeEventListener("keydown", onKeyDown);
 65→  }, [embedded]);
 66→
 67→  const submitMessage = async () => {
 68→    if (!input.trim() || isLoading) return;
 69→
 70→    const userMessage: Message = {
 71→      role: "user",
 72→      content: input.trim(),
 73→      timestamp: new Date(),
 74→    };
 75→
 76→    setInput("");
 77→    setError(null);
 78→    setIsLoading(true);
 79→    setMessages((prev) => [...prev, userMessage]);
 80→
 81→    try {
 82→      const response = await fetch("/api/chat", {
 83→        method: "POST",
 84→        headers: { "Content-Type": "application/json" },
 85→        body: JSON.stringify({
 86→          messages: [...messages, userMessage].map(({ role, content }) => ({ role, content })),
 87→        }),
 88→      });
 89→
 90→      if (!response.ok) {
 91→        throw new Error(`API error: ${response.statusText}`);
 92→      }
 93→
 94→      const reader = response.body?.getReader();
 95→      if (!reader) throw new Error("No response stream received");
 96→
 97→      const decoder = new TextDecoder();
 98→      let buffer = "";
 99→      let assistant: Message = {
100→        role: "assistant",
101→        content: "",
102→        toolCalls: [],
103→        timestamp: new Date(),
104→      };
105→
106→      while (true) {
107→        const { done, value } = await reader.read();
108→        if (done) break;
109→
110→        buffer += decoder.decode(value, { stream: true });
111→        const lines = buffer.split("\n");
112→        buffer = lines.pop() || "";
113→
114→        for (const line of lines) {
115→          if (!line.trim()) continue;
116→          let data: any;
117→          try {
118→            data = JSON.parse(line);
119→          } catch {
120→            continue;
121→          }
122→          if (data.content) assistant.content += data.content;
123→          if (data.toolCalls) assistant.toolCalls = [...(assistant.toolCalls || []), ...data.toolCalls];
124→
125→          setMessages((prev) => {
126→            const base = prev[prev.length - 1]?.role === "assistant" ? prev.slice(0, -1) : prev;
127→            return [...base, { ...assistant }];
128→          });
129→        }
130→      }
131→    } catch (err) {
132→      setError(err instanceof Error ? err.message : "Failed to send message");
133→      setMessages((prev) => [
134→        ...prev,
135→        {
136→          role: "assistant",
137→          content: "I hit an error while processing that. Please try again.",
138→          timestamp: new Date(),
139→        },
140→      ]);
141→    } finally {
142→      setIsLoading(false);
143→    }
144→  };
145→
146→  const containerClass = useMemo(() => {
147→    if (embedded) return "flex h-full min-h-0 flex-col";
148→    return "fixed bottom-4 right-4 z-50 flex h-[70vh] w-[min(94vw,380px)] flex-col overflow-hidden rounded-2xl border border-border bg-card shadow-2xl sm:bottom-6 sm:right-6";
149→  }, [embedded]);
150→
151→  if (!embedded && !isOpen) {
152→    return (
153→      <Button
154→        onClick={() => setIsOpen(true)}
155→        size="icon"
156→        className="fixed bottom-4 right-4 z-50 h-12 w-12 rounded-full shadow-lg sm:bottom-6 sm:right-6"
157→      >
158→        <Bot className="h-5 w-5" />
159→      </Button>
160→    );
161→  }
162→
163→  return (
164→    <section className={cn(containerClass, embedded ? "border-l border-border bg-card" : "")}>
165→      <header className="flex items-center justify-between border-b border-border px-4 py-3">
166→        <div className="flex items-center gap-2">
167→          <div className="flex h-7 w-7 items-center justify-center rounded-md bg-primary/10">
168→            <Sparkles className="h-3.5 w-3.5 text-primary" />
169→          </div>
170→          <div>
171→            <p className="text-sm font-semibold leading-none">Assistant</p>
172→            <p className="mt-1 text-[11px] text-muted-foreground">Agent-native mode</p>
173→          </div>
174→        </div>
175→        {!embedded && (
176→          <Button
177→            variant="ghost"
178→            size="icon"
179→            className="h-8 w-8"
180→            onClick={() => setIsOpen(false)}
181→            aria-label="Close chat"
182→          >
183→            <X className="h-4 w-4" />
184→          </Button>
185→        )}
186→      </header>
187→
188→      <div className="flex flex-wrap gap-1.5 border-b border-border px-3 py-2">
189→        {QUICK_ACTIONS.map((action) => (
190→          <button
191→            key={action.label}
192→            onClick={() => setInput(action.prompt)}
193→            disabled={isLoading}
194→            className="rounded-full border border-border bg-background px-2.5 py-1 text-[11px] text-muted-foreground transition-colors hover:bg-muted hover:text-foreground disabled:opacity-50"
195→          >
196→            {action.label}
197→          </button>
198→        ))}
199→      </div>
200→
201→      <ScrollArea className="min-h-0 flex-1 px-3 py-4">
202→        <div className="space-y-4">
203→          {messages.map((message, index) => (
204→            <div
205→              key={`${message.timestamp.getTime()}-${index}`}
206→              className={cn("flex gap-2.5", message.role === "user" ? "justify-end" : "justify-start")}
207→            >
208→              {message.role === "assistant" && (
209→                <div className="mt-1 flex h-6 w-6 items-center justify-center rounded-md bg-muted">
210→                  <Bot className="h-3.5 w-3.5 text-muted-foreground" />
211→                </div>
212→              )}
213→              <div
214→                className={cn(
215→                  "max-w-[86%] rounded-2xl px-3 py-2 text-sm leading-relaxed",
216→                  message.role === "user"
217→                    ? "bg-primary text-primary-foreground"
218→                    : "bg-muted text-foreground"
219→                )}
220→              >
221→                {message.content}
222→              </div>
223→              {message.role === "user" && (
224→                <div className="mt-1 flex h-6 w-6 items-center justify-center rounded-md bg-muted">
225→                  <User className="h-3.5 w-3.5 text-muted-foreground" />
226→                </div>
227→              )}
228→            </div>
229→          ))}
230→
231→          {isLoading && (
232→            <div className="flex items-center gap-2 text-xs text-muted-foreground">
233→              <Loader2 className="h-3.5 w-3.5 animate-spin" />
234→              Thinking
235→            </div>
236→          )}
237→
238→          {error && (
239→            <div className="rounded-xl border border-destructive/30 bg-destructive/10 px-3 py-2 text-xs text-destructive">
240→              {error}
241→            </div>
242→          )}
243→          <div ref={endRef} />
244→        </div>
245→      </ScrollArea>
246→
247→      <form
248→        className="border-t border-border px-3 py-3"
249→        onSubmit={(e) => {
250→          e.preventDefault();
251→          submitMessage();
252→        }}
253→      >
254→        <div className="flex items-center gap-2">
255→          <Input
256→            value={input}
257→            onChange={(e) => setInput(e.target.value)}
258→            placeholder="Ask the assistant..."
259→            className="h-10 rounded-xl bg-background"
260→            disabled={isLoading}
261→          />
262→          <Button type="submit" size="icon" className="h-10 w-10 rounded-xl" disabled={!input.trim() || isLoading}>
263→            <Send className="h-4 w-4" />
264→          </Button>
265→        </div>
266→      </form>
267→    </section>
268→  );
269→}
