 1→import { NextRequest, NextResponse } from "next/server";
 2→import { mastra } from "@/src/mastra";
 3→
 4→interface Message {
 5→  role: "user" | "assistant";
 6→  content: string;
 7→}
 8→
 9→function normalizeMessages(messages: Message[]) {
10→  return messages.map((m) => ({
11→    role: m.role,
12→    content: m.content,
13→  }));
14→}
15→
16→function extractToolCalls(output: any) {
17→  const calls = output?.toolCalls || output?.steps?.flatMap((step: any) => step?.toolCalls || []) || [];
18→  return calls.map((call: any) => ({
19→    name: call?.toolName || call?.name || "tool",
20→    args: call?.args || call?.input || {},
21→    result: call?.result,
22→  }));
23→}
24→
25→function extractContent(output: any): string {
26→  return (
27→    output?.text ||
28→    output?.outputText ||
29→    output?.response?.text ||
30→    output?.content ||
31→    "I completed the request."
32→  );
33→}
34→
35→export async function POST(request: NextRequest) {
36→  try {
37→    const body = await request.json();
38→    const { messages } = body as { messages?: Message[] };
39→
40→    if (!messages || !Array.isArray(messages) || messages.length === 0) {
41→      return NextResponse.json(
42→        { error: "Invalid request body. Expected non-empty 'messages' array." },
43→        { status: 400 }
44→      );
45→    }
46→
47→    const agent = mastra.getAgent("recruitmentAgent");
48→    if (!agent) {
49→      return NextResponse.json({ error: "Agent not found" }, { status: 500 });
50→    }
51→
52→    const normalizedMessages = normalizeMessages(messages);
53→    const result = await agent.generate(normalizedMessages as any);
54→
55→    const responsePayload = {
56→      role: "assistant",
57→      content: extractContent(result),
58→      toolCalls: extractToolCalls(result),
59→    };
60→
61→    const encoder = new TextEncoder();
62→    const stream = new ReadableStream({
63→      start(controller) {
64→        controller.enqueue(encoder.encode(`${JSON.stringify(responsePayload)}\n`));
65→        controller.close();
66→      },
67→    });
68→
69→    return new NextResponse(stream, {
70→      headers: {
71→        "Content-Type": "text/event-stream",
72→        "Cache-Control": "no-cache",
73→        Connection: "keep-alive",
74→      },
75→    });
76→  } catch (error) {
77→    return NextResponse.json(
78→      {
79→        error: error instanceof Error ? error.message : "Internal server error",
80→      },
81→      { status: 500 }
82→    );
83→  }
84→}
