 1→import { mastra } from '@/src/mastra';
 2→import { NextResponse } from 'next/server';
 3→
 4→/**
 5→ * POST /api/chat/stream
 6→ *
 7→ * Streaming chat endpoint for Mastra agents.
 8→ * Uses Server-Sent Events (SSE) to stream agent responses.
 9→ *
10→ * Request body:
11→ * {
12→ *   "message": "Find Java jobs in Utrecht",
13→ *   "agentId": "recruitment-agent" (optional)
14→ * }
15→ *
16→ * Response: text/event-stream with AI SDK protocol
17→ */
18→export async function POST(req: Request) {
19→  try {
20→    const body = await req.json();
21→    const { message, agentId = 'recruitmentAgent' } = body;
22→
23→    if (!message) {
24→      return NextResponse.json(
25→        { error: 'Message is required' },
26→        { status: 400 }
27→      );
28→    }
29→
30→    const agent = mastra.getAgent(agentId) || mastra.getAgent("recruitmentAgent");
31→
32→    if (!agent) {
33→      return NextResponse.json(
34→        { error: `Agent '${agentId}' not found` },
35→        { status: 404 }
36→      );
37→    }
38→
39→    const stream = await agent.stream(message);
40→    if (typeof (stream as any)?.toDataStreamResponse === "function") {
41→      return (stream as any).toDataStreamResponse();
42→    }
43→
44→    const result = await agent.generate(message);
45→    const response =
46→      (result as any)?.text ||
47→      (result as any)?.outputText ||
48→      (result as any)?.response?.text ||
49→      (result as any)?.content ||
50→      "";
51→    return NextResponse.json({ response });
52→  } catch (error) {
53→    console.error('Stream API error:', error);
54→    return NextResponse.json(
55→      { error: error instanceof Error ? error.message : 'Internal server error' },
56→      { status: 500 }
57→    );
58→  }
59→}
