  1→"use client";
  2→
  3→import { useChat } from "@ai-sdk/react";
  4→import type { UIMessage } from "ai";
  5→import { DefaultChatTransport } from "ai";
  6→import { nanoid } from "nanoid";
  7→import { useCallback, useState } from "react";
  8→import {
  9→  PromptInput,
 10→  PromptInputFooter,
 11→  type PromptInputMessage,
 12→  PromptInputSubmit,
 13→  PromptInputTextarea,
 14→} from "@/src/components/ai-elements/prompt-input";
 15→import { useChatContext } from "./chat-context-provider";
 16→import { ChatHistorySidebar } from "./chat-history-sidebar";
 17→import { ChatMessages } from "./chat-messages";
 18→
 19→function ChatSession({
 20→  sessionId,
 21→  initialMessages,
 22→  ctx,
 23→}: {
 24→  sessionId: string;
 25→  initialMessages?: UIMessage[];
 26→  ctx: { route: string; entityId: string | null; entityType: string | null };
 27→}) {
 28→  const { messages, sendMessage, status, stop } = useChat({
 29→    messages: initialMessages,
 30→    transport: new DefaultChatTransport({
 31→      api: "/api/chat",
 32→      body: {
 33→        context: {
 34→          route: ctx.route,
 35→          entityId: ctx.entityId,
 36→          entityType: ctx.entityType,
 37→          sessionId,
 38→        },
 39→      },
 40→    }),
 41→  });
 42→
 43→  const handleSubmit = useCallback(
 44→    (message: PromptInputMessage) => {
 45→      const text = message.text.trim();
 46→      if (!text) return;
 47→      sendMessage({ text });
 48→    },
 49→    [sendMessage],
 50→  );
 51→
 52→  return (
 53→    <>
 54→      <ChatMessages
 55→        messages={messages}
 56→        status={status}
 57→        onSuggestion={(text) => sendMessage({ text })}
 58→      />
 59→      <div className="border-t border-border p-3">
 60→        <PromptInput onSubmit={handleSubmit}>
 61→          <PromptInputTextarea placeholder="Stel een vraag..." />
 62→          <PromptInputFooter>
 63→            <div />
 64→            <PromptInputSubmit status={status} onStop={stop} />
 65→          </PromptInputFooter>
 66→        </PromptInput>
 67→      </div>
 68→    </>
 69→  );
 70→}
 71→
 72→export function ChatPageContent() {
 73→  const ctx = useChatContext();
 74→  const [sessionId, setSessionId] = useState(() => nanoid());
 75→  const [initialMessages, setInitialMessages] = useState<UIMessage[] | undefined>();
 76→  const [sidebarOpen, setSidebarOpen] = useState(true);
 77→
 78→  const handleSelectSession = useCallback(async (id: string) => {
 79→    try {
 80→      const res = await fetch(`/api/chat-sessies/${id}`);
 81→      if (res.ok) {
 82→        const session = await res.json();
 83→        setInitialMessages(session.messages ?? []);
 84→        setSessionId(id);
 85→      }
 86→    } catch {
 87→      // If fetch fails, just start a fresh session with that ID
 88→      setInitialMessages(undefined);
 89→      setSessionId(id);
 90→    }
 91→  }, []);
 92→
 93→  const handleNewSession = useCallback(() => {
 94→    setInitialMessages(undefined);
 95→    setSessionId(nanoid());
 96→  }, []);
 97→
 98→  return (
 99→    <div className="flex h-[calc(100vh-var(--sidebar-height,0px))]">
100→      {/* History sidebar — desktop only */}
101→      {sidebarOpen && (
102→        <ChatHistorySidebar
103→          activeSessionId={sessionId}
104→          onSelectSession={handleSelectSession}
105→          onNewSession={handleNewSession}
106→        />
107→      )}
108→
109→      {/* Main chat area */}
110→      <div className="flex flex-1 flex-col">
111→        <header className="flex h-12 shrink-0 items-center justify-between border-b border-border px-4">
112→          <div className="flex items-center gap-2">
113→            <button
114→              type="button"
115→              onClick={() => setSidebarOpen((prev) => !prev)}
116→              className="rounded-md p-1.5 text-muted-foreground transition-colors hover:bg-accent hover:text-foreground lg:hidden"
117→              title="Gesprekken"
118→            >
119→              <svg
120→                className="h-4 w-4"
121→                fill="none"
122→                stroke="currentColor"
123→                viewBox="0 0 24 24"
124→                role="img"
125→                aria-label="Gesprekken menu"
126→              >
127→                <path
128→                  strokeLinecap="round"
129→                  strokeLinejoin="round"
130→                  strokeWidth={2}
131→                  d="M4 6h16M4 12h16M4 18h16"
132→                />
133→              </svg>
134→            </button>
135→            <span className="text-sm font-semibold text-foreground">Motian AI</span>
136→          </div>
137→        </header>
138→
139→        {/* Chat session — key forces remount = clean state */}
140→        <ChatSession
141→          key={sessionId}
142→          sessionId={sessionId}
143→          initialMessages={initialMessages}
144→          ctx={ctx}
145→        />
146→      </div>
147→    </div>
148→  );
