 38→function ReasoningBlock({ text, state }: { text: string; state?: "streaming" | "done" }) {
 39→  const hasContent = text.length > 0;
 40→  const [expanded, setExpanded] = useState(hasContent || state === "streaming");
 41→
 42→  if (!hasContent && state !== "streaming") return null;
 43→
 44→  return (
 45→    <div className="my-2 rounded-lg border border-border bg-muted/50">
 46→      <button
 47→        type="button"
 48→        onClick={() => setExpanded((e) => !e)}
