 56→      {expanded && (
 57→        <div className="border-t border-border px-3 py-2">
 58→          <p className="whitespace-pre-wrap text-sm leading-relaxed text-muted-foreground">
 59→            {text}
 60→            {state === "streaming" && (
 61→              <span className="inline-block h-2 w-2 animate-pulse rounded-full bg-primary align-middle" />
