 96→export function ChatMessages({ messages, status, onSuggestion }: Props) {
 97→  if (messages.length === 0) {
 98→    return (
 99→      <div className="flex flex-1 flex-col items-center justify-center gap-4 p-6">
100→        <ConversationEmptyState
101→          icon={<Bot className="h-8 w-8" />}
102→          title="Motian AI"
103→          description="Beheer vacatures, kandidaten, matches, sollicitaties, interviews en berichten. Analyseer data en start scrapers."
104→        />
105→        <Suggestions className="justify-center">
106→          {EXAMPLE_PROMPTS.map((prompt) => (
107→            <Suggestion
108→              key={prompt}
109→              suggestion={prompt}
110→              onClick={(s) => onSuggestion?.(s)}
111→              variant="outline"
112→              size="sm"
113→              className="text-xs"
114→            />
115→          ))}
116→        </Suggestions>
117→      </div>
118→    );
119→  }
120→
121→  return (
122→    <Conversation className="flex-1">
123→      <ConversationContent className="gap-4 px-4 py-3">
124→        {messages.map((message) => (
125→          <Message key={message.id} from={message.role}>
126→            <MessageContent>
127→              {message.parts.map((part, partIndex) => {
128→                const partKey = `${message.id}-${partIndex}`;
129→                if (part.type === "text") {
130→                  if (message.role === "user") {
131→                    return (
132→                      <p key={partKey} className="whitespace-pre-wrap leading-relaxed">
133→                        {part.text}
134→                      </p>
135→                    );
136→                  }
137→                  return <MessageResponse key={partKey}>{part.text}</MessageResponse>;
138→                }
139→
140→                if (part.type === "reasoning") {
141→                  const reasoningPart = part as {
142→                    type: "reasoning";
143→                    text: string;
144→                    state?: "streaming" | "done";
145→                  };
146→                  return (
147→                    <ReasoningBlock
148→                      key={partKey}
149→                      text={reasoningPart.text}
150→                      state={reasoningPart.state}
151→                    />
152→                  );
153→                }
154→
155→                if (part.type === "source-url") {
156→                  const sourcePart = part as {
157→                    type: "source-url";
158→                    sourceId: string;
159→                    url: string;
160→                    title?: string;
161→                  };
162→                  return (
163→                    <SourceUrlBlock
164→                      key={partKey}
165→                      url={sourcePart.url}
166→                      title={sourcePart.title ?? sourcePart.url}
167→                    />
168→                  );
169→                }
170→
171→                if (part.type === "source-document") {
172→                  const docPart = part as {
173→                    type: "source-document";
174→                    sourceId: string;
175→                    mediaType: string;
176→                    title: string;
177→                  };
178→                  return (
179→                    <SourceDocumentBlock
180→                      key={partKey}
181→                      title={docPart.title}
182→                      mediaType={docPart.mediaType}
183→                    />
184→                  );
185→                }
186→
187→                if (isToolUIPart(part)) {
188→                  const toolPart = part as {
189→                    type: string;
190→                    toolName?: string;
191→                    state: string;
192→                    input?: unknown;
193→                    output?: unknown;
194→                  };
195→                  const name = toolPart.toolName ?? getToolName(part);
196→                  const GenUICard = name ? GENUI_COMPONENTS[name] : undefined;
197→                  const isErrorOutput =
198→                    toolPart.output &&
199→                    typeof toolPart.output === "object" &&
200→                    "error" in toolPart.output;
201→
202→                  if (toolPart.state === "output-error") {
203→                    const msg =
204→                      toolPart.output &&
205→                      typeof toolPart.output === "object" &&
206→                      "error" in toolPart.output &&
207→                      typeof (toolPart.output as { error: unknown }).error === "string"
208→                        ? (toolPart.output as { error: string }).error
209→                        : "Er is iets misgegaan bij deze actie.";
210→                    return <ToolErrorBlock key={partKey} message={msg} />;
211→                  }
212→                  if (
213→                    toolPart.state === "output-available" &&
214→                    GenUICard &&
215→                    toolPart.output !== undefined
216→                  ) {
217→                    if (isErrorOutput) {
218→                      const msg =
219→                        typeof (toolPart.output as { error: unknown }).error === "string"
220→                          ? (toolPart.output as { error: string }).error
221→                          : "Niet gevonden.";
222→                      return <ToolErrorBlock key={partKey} message={msg} />;
223→                    }
224→                    return <GenUICard key={partKey} output={toolPart.output} />;
225→                  }
226→                  return (
227→                    <ChatToolCall
228→                      key={partKey}
229→                      toolName={name}
230→                      state={toolPart.state}
231→                      input={toolPart.input}
232→                      output={toolPart.output}
233→                    />
234→                  );
235→                }
236→
237→                return null;
238→              })}
239→            </MessageContent>
240→          </Message>
241→        ))}
242→
243→        {(status === "streaming" || status === "submitted") &&
244→          messages.at(-1)?.role !== "assistant" && (
245→            <div className="flex items-center gap-1.5 text-sm text-muted-foreground">
246→              <span className="inline-block h-2 w-2 animate-pulse rounded-full bg-primary" />
247→              Denkt na...
248→            </div>
249→          )}
250→      </ConversationContent>
251→      <ConversationScrollButton />
252→    </Conversation>
253→  );
254→}
