 22→function timeAgo(dateStr: string | null): string {
 23→  if (!dateStr) return "";
 24→  const diff = Date.now() - new Date(dateStr).getTime();
 25→  const mins = Math.floor(diff / 60000);
 26→  if (mins < 1) return "zojuist";
 27→  if (mins < 60) return `${mins}m geleden`;
 28→  const hours = Math.floor(mins / 60);
 29→  if (hours < 24) return `${hours}u geleden`;
 30→  const days = Math.floor(hours / 24);
 31→  if (days < 7) return `${days}d geleden`;
 32→  return new Date(dateStr).toLocaleDateString("nl-NL", { day: "numeric", month: "short" });
 33→}
