22→export function ChatContextProvider({ children }: { children: ReactNode }) {
23→  const pathname = usePathname();
24→  const params = useParams<{ id?: string }>();
25→
26→  const value = useMemo<ChatContext>(() => {
27→    const id = params?.id ?? null;
28→
29→    if (pathname.startsWith("/opdrachten/") && id) {
30→      return { route: pathname, entityType: "opdracht", entityId: id };
31→    }
32→    if (pathname.startsWith("/professionals/") && id) {
