 28→  if (!success) {
 29→    return Response.json(
 30→      { error: "Te veel verzoeken. Probeer het later opnieuw." },
 31→      { status: 429, headers: { "Retry-After": String(Math.ceil((reset - Date.now()) / 1000)) } },
 32→    );
 33→  }
 34→
 35→  const body = await req.json().catch(() => null);
 36→  if (!body || !Array.isArray(body.messages)) {
 37→    return Response.json({ error: "Ongeldige aanvraag" }, { status: 400 });
 38→  }
 39→
 40→  const contextResult = contextSchema.safeParse(body.context);
 41→  if (!contextResult.success) {
 42→    return Response.json({ error: "Ongeldige context" }, { status: 400 });
 43→  }
 44→
 45→  const ctx = contextResult.data ?? undefined;
 46→  const sessionId = ctx?.sessionId;
 47→
 48→  // Persist conversation using after() — runs after response streams, guaranteed to complete
 49→  if (sessionId) {
 50→    const lastMessages = body.messages.slice(-MAX_STORED_MESSAGES);
 51→    const lastUserMsg = [...body.messages]
 52→      .reverse()
 53→      .find((m: { role: string }) => m.role === "user");
 54→    const preview =
 55→      typeof lastUserMsg?.content === "string" ? lastUserMsg.content.slice(0, 100) : null;
 56→
 57→    // Extract title from first user message (only set once)
 58→    const firstUserMsg = body.messages.find((m: { role: string }) => m.role === "user");
 59→    const title =
 60→      typeof firstUserMsg?.content === "string" ? firstUserMsg.content.slice(0, 60) : null;
 61→
 62→    after(async () => {
 63→      try {
 64→        await db
 65→          .insert(chatSessions)
 66→          .values({
 67→            sessionId,
 68→            messages: lastMessages,
 69→            context: ctx,
 70→            messageCount: lastMessages.length,
 71→            title,
 72→            lastMessagePreview: preview,
 73→          })
 74→          .onConflictDoUpdate({
 75→            target: chatSessions.sessionId,
 76→            set: {
 77→              messages: lastMessages,
 78→              context: ctx,
 79→              messageCount: lastMessages.length,
 80→              lastMessagePreview: preview,
 81→              updatedAt: new Date(),
 82→            },
 83→          });
 84→      } catch (err) {
 85→        console.error("[chat] Session persistence failed:", err);
 86→      }
 87→    });
 88→  }
 89→
 90→  const system = await buildSystemPrompt(ctx);
 91→
 92→  const result = streamText({
 93→    model: chatModel,
 94→    system,
 95→    messages: await convertToModelMessages(body.messages),
 96→    tools: recruitmentTools,
 97→    stopWhen: stepCountIs(5),
 98→  });
 99→
100→  return result.toUIMessageStreamResponse({
101→    sendReasoning: true,
102→    sendSources: true,
103→  });
104→}
