 21→
 22→  // Auto-dismiss success/error messages (but not matching)
 23→  useEffect(() => {
 24→    if (status === "success" || status === "error") {
 25→      const timer = setTimeout(() => {
 26→        setStatus("idle");
 27→        setMessage(null);
 28→        setMatchCandidateId(null);
 29→      }, 30000);
 30→      return () => clearTimeout(timer);
 31→    }
 32→  }, [status]);
 33→
 34→  const processFile = useCallback(
 35→    async (file: File) => {
 36→      const validTypes = [
 37→        "application/pdf",
 38→        "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
 39→      ];
 40→      if (!validTypes.includes(file.type)) {
 41→        setStatus("error");
 42→        setMessage("Alleen PDF en Word (.docx) bestanden zijn toegestaan");
 43→        return;
 44→      }
 45→      if (file.size > 20 * 1024 * 1024) {
 46→        setStatus("error");
 47→        setMessage("Bestand is te groot. Maximaal 20MB.");
 48→        return;
 49→      }
 50→
 51→      setStatus("uploading");
 52→      setMessage("CV wordt verwerkt...");
 53→
 54→      try {
 55→        // Phase 1: Upload & parse
 56→        const formData = new FormData();
 57→        formData.append("cv", file);
 58→        const uploadRes = await fetch("/api/cv-upload", {
 59→          method: "POST",
 60→          body: formData,
 61→        });
 62→        if (!uploadRes.ok) {
 63→          const json = await uploadRes.json();
 64→          throw new Error(json.error ?? "Upload mislukt");
 65→        }
 66→        const { parsed, fileUrl } = await uploadRes.json();
 67→
 68→        // Phase 2: Save candidate
 69→        setMessage("Profiel wordt bijgewerkt...");
 70→        const saveRes = await fetch("/api/cv-upload/save", {
 71→          method: "POST",
 72→          headers: { "Content-Type": "application/json" },
 73→          body: JSON.stringify({ parsed, fileUrl, existingCandidateId: candidateId }),
 74→        });
 75→        if (!saveRes.ok) throw new Error("Opslaan mislukt");
