 78→        router.refresh();
 79→
 80→        // Phase 3: Auto-matching
 81→        const resolvedCandidateId = saveData.candidateId ?? candidateId;
 82→        setStatus("matching");
 83→        setMessage("Vacatures worden gescand...");
 84→        setMatchCandidateId(resolvedCandidateId);
 85→      } catch (err) {
 86→        setStatus("error");
 87→        setMessage(err instanceof Error ? err.message : "Onbekende fout");
 88→      }
 89→    },
 90→    [candidateId, router],
 91→  );
