 1→import { eq } from "drizzle-orm";
 2→import type { NextRequest } from "next/server";
 3→import { z } from "zod";
 4→import { db } from "@/src/db";
 5→import { candidates } from "@/src/db/schema";
 6→import { deleteFile } from "@/src/lib/file-storage";
 7→
 8→export const dynamic = "force-dynamic";
 9→
10→const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
11→
12→const patchSchema = z.object({
13→  name: z.string().min(1).max(200).optional(),
14→  role: z.string().max(200).nullable().optional(),
15→  email: z.string().email().nullable().optional(),
16→  phone: z.string().max(50).nullable().optional(),
17→});
18→
19→/** PATCH /api/candidates/[id] — update candidate fields */
20→export async function PATCH(request: NextRequest, { params }: { params: Promise<{ id: string }> }) {
21→  const { id } = await params;
22→  if (!UUID_RE.test(id)) {
23→    return Response.json({ error: "Ongeldig ID" }, { status: 400 });
24→  }
25→
26→  const body = await request.json();
27→  const parsed = patchSchema.safeParse(body);
28→  if (!parsed.success) {
29→    return Response.json({ error: parsed.error.flatten().fieldErrors }, { status: 400 });
30→  }
31→
32→  const updates = parsed.data;
33→  if (Object.keys(updates).length === 0) {
34→    return Response.json({ error: "Geen velden om bij te werken" }, { status: 400 });
35→  }
36→
37→  const [updated] = await db
38→    .update(candidates)
39→    .set({ ...updates, updatedAt: new Date() })
40→    .where(eq(candidates.id, id))
41→    .returning({ id: candidates.id, name: candidates.name });
42→
43→  if (!updated) {
44→    return Response.json({ error: "Kandidaat niet gevonden" }, { status: 404 });
45→  }
46→
47→  return Response.json(updated);
48→}
49→
50→/** DELETE /api/candidates/[id] — soft-delete candidate + remove blob file */
51→export async function DELETE(
52→  _request: NextRequest,
53→  { params }: { params: Promise<{ id: string }> },
54→) {
55→  const { id } = await params;
56→  if (!UUID_RE.test(id)) {
57→    return Response.json({ error: "Ongeldig ID" }, { status: 400 });
58→  }
59→
60→  // Get the resume URL before soft-deleting
61→  const [candidate] = await db
62→    .select({ id: candidates.id, resumeUrl: candidates.resumeUrl })
63→    .from(candidates)
64→    .where(eq(candidates.id, id))
65→    .limit(1);
66→
67→  if (!candidate) {
68→    return Response.json({ error: "Kandidaat niet gevonden" }, { status: 404 });
69→  }
70→
71→  // Soft-delete the candidate
72→  await db
73→    .update(candidates)
74→    .set({ deletedAt: new Date(), updatedAt: new Date() })
75→    .where(eq(candidates.id, id));
76→
77→  // Clean up blob storage (fire-and-forget)
78→  if (candidate.resumeUrl) {
79→    deleteFile(candidate.resumeUrl).catch((err) =>
80→      console.error("[Candidates] Failed to delete blob:", err),
81→    );
82→  }
83→
84→  return Response.json({ deleted: true });
85→}
