 1→import type { NextRequest } from "next/server";
 2→import { uploadFile } from "@/src/lib/file-storage";
 3→import { rateLimit } from "@/src/lib/rate-limit";
 4→import { findDuplicateCandidate } from "@/src/services/candidates";
 5→import { parseCV } from "@/src/services/cv-parser";
 6→
 7→export const dynamic = "force-dynamic";
 8→
 9→const limiter = rateLimit({ interval: 60_000, limit: 10 });
10→
11→const ALLOWED_TYPES = [
12→  "application/pdf",
13→  "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
14→] as const;
15→
16→const MAX_SIZE_MB = 20;
17→
18→export async function POST(request: NextRequest) {
19→  const ip =
20→    request.headers.get("x-real-ip") ??
21→    request.headers.get("x-forwarded-for")?.split(",")[0].trim() ??
22→    "anonymous";
23→  const { success, reset } = limiter.check(ip);
24→  if (!success) {
25→    return Response.json(
26→      { error: "Te veel verzoeken. Probeer het later opnieuw." },
27→      { status: 429, headers: { "Retry-After": String(Math.ceil((reset - Date.now()) / 1000)) } },
28→    );
29→  }
30→
31→  try {
32→    // Early check for required env vars
33→    if (!process.env.BLOB_READ_WRITE_TOKEN) {
34→      console.error("[CV Upload] BLOB_READ_WRITE_TOKEN is not configured");
35→      return Response.json(
36→        { error: "Bestandsopslag is niet geconfigureerd. Stel BLOB_READ_WRITE_TOKEN in." },
37→        { status: 503 },
38→      );
39→    }
40→
41→    const formData = await request.formData();
42→    const file = formData.get("cv") as File | null;
43→
44→    if (!file) {
45→      return Response.json({ error: "Geen bestand ontvangen" }, { status: 400 });
46→    }
47→
48→    // Validate type
49→    const mimeType = file.type;
50→    if (!ALLOWED_TYPES.includes(mimeType as (typeof ALLOWED_TYPES)[number])) {
51→      return Response.json(
52→        { error: "Ongeldig bestandstype. Alleen PDF en Word (.docx) zijn toegestaan." },
53→        { status: 400 },
54→      );
55→    }
56→
57→    // Validate size
58→    if (file.size > MAX_SIZE_MB * 1024 * 1024) {
59→      return Response.json(
60→        { error: `Bestand te groot. Maximaal ${MAX_SIZE_MB}MB toegestaan.` },
61→        { status: 400 },
62→      );
63→    }
64→
65→    // Upload to blob storage
66→    const buffer = Buffer.from(await file.arrayBuffer());
67→    const { url: fileUrl } = await uploadFile(buffer, `cv/${Date.now()}-${file.name}`, mimeType);
68→
69→    // Parse CV with Gemini
70→    const parsed = await parseCV(
71→      buffer,
72→      mimeType as
73→        | "application/pdf"
74→        | "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
75→    );
76→
77→    // Check for duplicates
78→    const duplicates = await findDuplicateCandidate(parsed);
79→
80→    return Response.json({
81→      parsed,
82→      fileUrl,
83→      duplicates: {
84→        exact: duplicates.exact,
85→        similar: duplicates.similar,
86→      },
87→    });
88→  } catch (err) {
89→    const message = err instanceof Error ? err.message : "Onbekende fout";
90→    console.error("[CV Upload] Error:", message, err);
91→    return Response.json({ error: `CV verwerking mislukt: ${message}` }, { status: 500 });
92→  }
93→}
