  70→    // FileReader uses callback-based API, wrapping in Promise is necessary
  71→    // oxlint-disable-next-line eslint-plugin-promise(avoid-new)
  72→    return new Promise((resolve) => {
  73→      const reader = new FileReader();
  74→      // oxlint-disable-next-line eslint-plugin-unicorn(prefer-add-event-listener)
