 159→  const openRef = useRef<() => void>(() => {});
 160→
 161→  const add = useCallback((files: File[] | FileList) => {
 162→    const incoming = [...files];
 163→    if (incoming.length === 0) {
 164→      return;
 165→    }
 166→
 167→    setAttachmentFiles((prev) => [
 168→      ...prev,
 169→      ...incoming.map((file) => ({
 170→        filename: file.name,
 171→        id: nanoid(),
 172→        mediaType: file.type,
 173→        type: "file" as const,
 174→        url: URL.createObjectURL(file),
 175→      })),
 176→    ]);
 177→  }, []);
 178→
 179→  const remove = useCallback((id: string) => {
 180→    setAttachmentFiles((prev) => {
 181→      const found = prev.find((f) => f.id === id);
 182→      if (found?.url) {
 183→        URL.revokeObjectURL(found.url);
 184→      }
 185→      return prev.filter((f) => f.id !== id);
 186→    });
 187→  }, []);
 188→
 189→  const clear = useCallback(() => {
 190→    setAttachmentFiles((prev) => {
 191→      for (const f of prev) {
 192→        if (f.url) {
 193→          URL.revokeObjectURL(f.url);
 194→        }
 195→      }
 196→      return [];
 197→    });
 198→  }, []);
 199→
 200→  // Keep a ref to attachments for cleanup on unmount (avoids stale closure)
 201→  const attachmentsRef = useRef(attachmentFiles);
 202→
 203→  useEffect(() => {
 204→    attachmentsRef.current = attachmentFiles;
 205→  }, [attachmentFiles]);
 206→
 207→  // Cleanup blob URLs on unmount to prevent memory leaks
 208→  useEffect(
 209→    () => () => {
 210→      for (const f of attachmentsRef.current) {
 211→        if (f.url) {
 212→          URL.revokeObjectURL(f.url);
 213→        }
 214→      }
 215→    },
 216→    [],
 217→  );
 218→
 219→  const openFileDialog = useCallback(() => {
 220→    openRef.current?.();
 221→  }, []);
 222→
 223→  const attachments = useMemo<AttachmentsContext>(
 224→    () => ({
 225→      add,
 226→      clear,
 227→      fileInputRef,
 228→      files: attachmentFiles,
 229→      openFileDialog,
 230→      remove,
 231→    }),
 232→    [attachmentFiles, add, remove, clear, openFileDialog],
 233→  );
 234→
 235→  const __registerFileInput = useCallback(
 236→    (ref: RefObject<HTMLInputElement | null>, open: () => void) => {
 237→      fileInputRef.current = ref.current;
 238→      openRef.current = open;
 239→    },
 240→    [],
 241→  );
 242→
 243→  const controller = useMemo<PromptInputControllerProps>(
 244→    () => ({
 245→      __registerFileInput,
 246→      attachments,
 247→      textInput: {
 248→        clear: clearInput,
 249→        setInput: setTextInput,
 250→        value: textInput,
 251→      },
 252→    }),
 253→    [textInput, clearInput, attachments, __registerFileInput],
 254→  );
 255→
 256→  return (
 257→    <PromptInputController.Provider value={controller}>
 258→      <ProviderAttachmentsContext.Provider value={attachments}>
 259→        {children}
 260→      </ProviderAttachmentsContext.Provider>
 261→    </PromptInputController.Provider>
 262→  );
 263→};
