 271→export const usePromptInputAttachments = () => {
 272→  // Prefer local context (inside PromptInput) as it has validation, fall back to provider
 273→  const provider = useOptionalProviderAttachments();
 274→  const local = useContext(LocalAttachmentsContext);
 275→  const context = local ?? provider;
 276→  if (!context) {
 277→    throw new Error(
 278→      "usePromptInputAttachments must be used within a PromptInput or PromptInputProvider",
 279→    );
 280→  }
 281→  return context;
 282→};
