 331→
 332→export interface PromptInputMessage {
 333→  text: string;
 334→  files: FileUIPart[];
 335→}
 336→
 337→export type PromptInputProps = Omit<HTMLAttributes<HTMLFormElement>, "onSubmit" | "onError"> & {
 338→  // e.g., "image/*" or leave undefined for any
 339→  accept?: string;
 340→  multiple?: boolean;
 341→  // When true, accepts drops anywhere on document. Default false (opt-in).
 342→  globalDrop?: boolean;
 343→  // Render a hidden input with given name and keep it in sync for native form posts. Default false.
 344→  syncHiddenInput?: boolean;
 345→  // Minimal constraints
 346→  maxFiles?: number;
 347→  // bytes
 348→  maxFileSize?: number;
 349→  onError?: (err: { code: "max_files" | "max_file_size" | "accept"; message: string }) => void;
 350→  onSubmit: (
 351→    message: PromptInputMessage,
 352→    event: FormEvent<HTMLFormElement>,
 353→  ) => void | Promise<void>;
 354→};
 355→
 356→export const PromptInput = ({
 357→  className,
 358→  accept,
 359→  multiple,
 360→  globalDrop,
 361→  syncHiddenInput,
 362→  maxFiles,
 363→  maxFileSize,
 364→  onError,
 365→  onSubmit,
 366→  children,
 367→  ...props
 368→}: PromptInputProps) => {
 369→  // Try to use a provider controller if present
 370→  const controller = useOptionalPromptInputController();
 371→  const usingProvider = !!controller;
 372→
 373→  // Refs
 374→  const inputRef = useRef<HTMLInputElement | null>(null);
 375→  const formRef = useRef<HTMLFormElement | null>(null);
 376→
 377→  // ----- Local attachments (only used when no provider)
 378→  const [items, setItems] = useState<(FileUIPart & { id: string })[]>([]);
 379→  const files = usingProvider ? controller.attachments.files : items;
 380→
 381→  // ----- Local referenced sources (always local to PromptInput)
 382→  const [referencedSources, setReferencedSources] = useState<
 383→    (SourceDocumentUIPart & { id: string })[]
 384→  >([]);
 385→
 386→  // Keep a ref to files for cleanup on unmount (avoids stale closure)
 387→  const filesRef = useRef(files);
 388→
 389→  useEffect(() => {
 390→    filesRef.current = files;
 391→  }, [files]);
 392→
 393→  const openFileDialogLocal = useCallback(() => {
 394→    inputRef.current?.click();
 395→  }, []);
 396→
 397→  const matchesAccept = useCallback(
 398→    (f: File) => {
 399→      if (!accept || accept.trim() === "") {
 400→        return true;
 401→      }
 402→
 403→      const patterns = accept
 404→        .split(",")
 405→        .map((s) => s.trim())
 406→        .filter(Boolean);
 407→
 408→      return patterns.some((pattern) => {
 409→        if (pattern.endsWith("/*")) {
 410→          // e.g: image/* -> image/
 411→          const prefix = pattern.slice(0, -1);
 412→          return f.type.startsWith(prefix);
 413→        }
 414→        return f.type === pattern;
 415→      });
 416→    },
 417→    [accept],
 418→  );
 419→
 420→  const addLocal = useCallback(
 421→    (fileList: File[] | FileList) => {
 422→      const incoming = [...fileList];
 423→      const accepted = incoming.filter((f) => matchesAccept(f));
 424→      if (incoming.length && accepted.length === 0) {
 425→        onError?.({
 426→          code: "accept",
 427→          message: "No files match the accepted types.",
 428→        });
 429→        return;
 430→      }
 431→      const withinSize = (f: File) => (maxFileSize ? f.size <= maxFileSize : true);
 432→      const sized = accepted.filter(withinSize);
 433→      if (accepted.length > 0 && sized.length === 0) {
 434→        onError?.({
 435→          code: "max_file_size",
 436→          message: "All files exceed the maximum size.",
 437→        });
 438→        return;
 439→      }
 440→
 441→      setItems((prev) => {
 442→        const capacity =
 443→          typeof maxFiles === "number" ? Math.max(0, maxFiles - prev.length) : undefined;
 444→        const capped = typeof capacity === "number" ? sized.slice(0, capacity) : sized;
 445→        if (typeof capacity === "number" && sized.length > capacity) {
 446→          onError?.({
 447→            code: "max_files",
 448→            message: "Too many files. Some were not added.",
 449→          });
 450→        }
 451→        const next: (FileUIPart & { id: string })[] = [];
 452→        for (const file of capped) {
 453→          next.push({
 454→            filename: file.name,
 455→            id: nanoid(),
 456→            mediaType: file.type,
 457→            type: "file",
 458→            url: URL.createObjectURL(file),
 459→          });
 460→        }
 461→        return [...prev, ...next];
 462→      });
 463→    },
 464→    [matchesAccept, maxFiles, maxFileSize, onError],
 465→  );
 466→
 467→  const removeLocal = useCallback(
 468→    (id: string) =>
 469→      setItems((prev) => {
 470→        const found = prev.find((file) => file.id === id);
 471→        if (found?.url) {
 472→          URL.revokeObjectURL(found.url);
 473→        }
 474→        return prev.filter((file) => file.id !== id);
 475→      }),
 476→    [],
 477→  );
 478→
 479→  // Wrapper that validates files before calling provider's add
 480→  const addWithProviderValidation = useCallback(
 481→    (fileList: File[] | FileList) => {
 482→      const incoming = [...fileList];
 483→      const accepted = incoming.filter((f) => matchesAccept(f));
 484→      if (incoming.length && accepted.length === 0) {
 485→        onError?.({
 486→          code: "accept",
 487→          message: "No files match the accepted types.",
 488→        });
 489→        return;
 490→      }
 491→      const withinSize = (f: File) => (maxFileSize ? f.size <= maxFileSize : true);
 492→      const sized = accepted.filter(withinSize);
 493→      if (accepted.length > 0 && sized.length === 0) {
 494→        onError?.({
 495→          code: "max_file_size",
 496→          message: "All files exceed the maximum size.",
 497→        });
 498→        return;
 499→      }
 500→
 501→      const currentCount = files.length;
 502→      const capacity =
 503→        typeof maxFiles === "number" ? Math.max(0, maxFiles - currentCount) : undefined;
 504→      const capped = typeof capacity === "number" ? sized.slice(0, capacity) : sized;
 505→      if (typeof capacity === "number" && sized.length > capacity) {
 506→        onError?.({
 507→          code: "max_files",
 508→          message: "Too many files. Some were not added.",
 509→        });
 510→      }
 511→
 512→      if (capped.length > 0) {
 513→        controller?.attachments.add(capped);
 514→      }
 515→    },
 516→    [matchesAccept, maxFileSize, maxFiles, onError, files.length, controller],
 517→  );
 518→
 519→  const clearAttachments = useCallback(
 520→    () =>
 521→      usingProvider
 522→        ? controller?.attachments.clear()
 523→        : setItems((prev) => {
 524→            for (const file of prev) {
 525→              if (file.url) {
 526→                URL.revokeObjectURL(file.url);
 527→              }
 528→            }
 529→            return [];
 530→          }),
 531→    [usingProvider, controller],
 532→  );
 533→
 534→  const clearReferencedSources = useCallback(() => setReferencedSources([]), []);
 535→
 536→  const add = usingProvider ? addWithProviderValidation : addLocal;
 537→  const remove = usingProvider ? controller.attachments.remove : removeLocal;
 538→  const openFileDialog = usingProvider
 539→    ? controller.attachments.openFileDialog
 540→    : openFileDialogLocal;
 541→
 542→  const clear = useCallback(() => {
 543→    clearAttachments();
 544→    clearReferencedSources();
 545→  }, [clearAttachments, clearReferencedSources]);
 546→
 547→  // Let provider know about our hidden file input so external menus can call openFileDialog()
 548→  useEffect(() => {
 549→    if (!usingProvider) {
 550→      return;
 551→    }
 552→    controller.__registerFileInput(inputRef, () => inputRef.current?.click());
 553→  }, [usingProvider, controller]);
 554→
 555→  // Note: File input cannot be programmatically set for security reasons
 556→  // The syncHiddenInput prop is no longer functional
 557→  useEffect(() => {
 558→    if (syncHiddenInput && inputRef.current && files.length === 0) {
 559→      inputRef.current.value = "";
 560→    }
 561→  }, [files, syncHiddenInput]);
 562→
 563→  // Attach drop handlers on nearest form and document (opt-in)
 564→  useEffect(() => {
 565→    const form = formRef.current;
 566→    if (!form) {
 567→      return;
 568→    }
 569→    if (globalDrop) {
 570→      // when global drop is on, let the document-level handler own drops
 571→      return;
 572→    }
 573→
 574→    const onDragOver = (e: DragEvent) => {
 575→      if (e.dataTransfer?.types?.includes("Files")) {
 576→        e.preventDefault();
 577→      }
 578→    };
 579→    const onDrop = (e: DragEvent) => {
 580→      if (e.dataTransfer?.types?.includes("Files")) {
 581→        e.preventDefault();
 582→      }
 583→      if (e.dataTransfer?.files && e.dataTransfer.files.length > 0) {
 584→        add(e.dataTransfer.files);
 585→      }
 586→    };
 587→    form.addEventListener("dragover", onDragOver);
 588→    form.addEventListener("drop", onDrop);
 589→    return () => {
 590→      form.removeEventListener("dragover", onDragOver);
 591→      form.removeEventListener("drop", onDrop);
 592→    };
 593→  }, [add, globalDrop]);
 594→
 595→  useEffect(() => {
 596→    if (!globalDrop) {
 597→      return;
 598→    }
 599→
 600→    const onDragOver = (e: DragEvent) => {
 601→      if (e.dataTransfer?.types?.includes("Files")) {
 602→        e.preventDefault();
 603→      }
 604→    };
 605→    const onDrop = (e: DragEvent) => {
 606→      if (e.dataTransfer?.types?.includes("Files")) {
 607→        e.preventDefault();
 608→      }
 609→      if (e.dataTransfer?.files && e.dataTransfer.files.length > 0) {
 610→        add(e.dataTransfer.files);
 611→      }
 612→    };
 613→    document.addEventListener("dragover", onDragOver);
 614→    document.addEventListener("drop", onDrop);
 615→    return () => {
 616→      document.removeEventListener("dragover", onDragOver);
 617→      document.removeEventListener("drop", onDrop);
 618→    };
 619→  }, [add, globalDrop]);
 620→
 621→  useEffect(
 622→    () => () => {
 623→      if (!usingProvider) {
 624→        for (const f of filesRef.current) {
 625→          if (f.url) {
 626→            URL.revokeObjectURL(f.url);
 627→          }
 628→        }
 629→      }
 630→    },
 631→    // eslint-disable-next-line react-hooks/exhaustive-deps -- cleanup only on unmount; filesRef always current
 632→    [usingProvider],
 633→  );
 634→
 635→  const handleChange: ChangeEventHandler<HTMLInputElement> = useCallback(
 636→    (event) => {
 637→      if (event.currentTarget.files) {
 638→        add(event.currentTarget.files);
 639→      }
 640→      // Reset input value to allow selecting files that were previously removed
 641→      event.currentTarget.value = "";
 642→    },
 643→    [add],
 644→  );
 645→
 646→  const attachmentsCtx = useMemo<AttachmentsContext>(
 647→    () => ({
 648→      add,
 649→      clear: clearAttachments,
 650→      fileInputRef: inputRef,
 651→      files: files.map((item) => ({ ...item, id: item.id })),
 652→      openFileDialog,
 653→      remove,
 654→    }),
 655→    [files, add, remove, clearAttachments, openFileDialog],
 656→  );
 657→
 658→  const refsCtx = useMemo<ReferencedSourcesContext>(
 659→    () => ({
 660→      add: (incoming: SourceDocumentUIPart[] | SourceDocumentUIPart) => {
 661→        const array = Array.isArray(incoming) ? incoming : [incoming];
 662→        setReferencedSources((prev) => [...prev, ...array.map((s) => ({ ...s, id: nanoid() }))]);
 663→      },
 664→      clear: clearReferencedSources,
 665→      remove: (id: string) => {
 666→        setReferencedSources((prev) => prev.filter((s) => s.id !== id));
 667→      },
 668→      sources: referencedSources,
 669→    }),
 670→    [referencedSources, clearReferencedSources],
 671→  );
 672→
 673→  const handleSubmit: FormEventHandler<HTMLFormElement> = useCallback(
 674→    async (event) => {
 675→      event.preventDefault();
 676→
 677→      const form = event.currentTarget;
 678→      const text = usingProvider
 679→        ? controller.textInput.value
 680→        : (() => {
 681→            const formData = new FormData(form);
 682→            return (formData.get("message") as string) || "";
 683→          })();
 684→
 685→      // Reset form immediately after capturing text to avoid race condition
 686→      // where user input during async blob conversion would be lost
 687→      if (!usingProvider) {
 688→        form.reset();
 689→      }
 690→
 691→      try {
 692→        // Convert blob URLs to data URLs asynchronously
 693→        const convertedFiles: FileUIPart[] = await Promise.all(
 694→          files.map(async ({ id: _id, ...item }) => {
 695→            if (item.url?.startsWith("blob:")) {
 696→              const dataUrl = await convertBlobUrlToDataUrl(item.url);
 697→              // If conversion failed, keep the original blob URL
 698→              return {
 699→                ...item,
 700→                url: dataUrl ?? item.url,
 701→              };
 702→            }
 703→            return item;
 704→          }),
 705→        );
 706→
 707→        const result = onSubmit({ files: convertedFiles, text }, event);
 708→
 709→        // Handle both sync and async onSubmit
 710→        if (result instanceof Promise) {
 711→          try {
 712→            await result;
 713→            clear();
 714→            if (usingProvider) {
 715→              controller.textInput.clear();
 716→            }
 717→          } catch {
 718→            // Don't clear on error - user may want to retry
 719→          }
 720→        } else {
 721→          // Sync function completed without throwing, clear inputs
 722→          clear();
 723→          if (usingProvider) {
 724→            controller.textInput.clear();
 725→          }
 726→        }
 727→      } catch {
 728→        // Don't clear on error - user may want to retry
 729→      }
 730→    },
 731→    [usingProvider, controller, files, onSubmit, clear],
 732→  );
 733→
 734→  // Render with or without local provider
 735→  const inner = (
 736→    <>
 737→      <input
 738→        accept={accept}
 739→        aria-label="Upload files"
 740→        className="hidden"
 741→        multiple={multiple}
 742→        onChange={handleChange}
 743→        ref={inputRef}
 744→        title="Upload files"
 745→        type="file"
 746→      />
 747→      <form className={cn("w-full", className)} onSubmit={handleSubmit} ref={formRef} {...props}>
 748→        <InputGroup className="overflow-hidden">{children}</InputGroup>
 749→      </form>
 750→    </>
 751→  );
 752→
 753→  const withReferencedSources = (
 754→    <LocalReferencedSourcesContext.Provider value={refsCtx}>
 755→      {inner}
 756→    </LocalReferencedSourcesContext.Provider>
 757→  );
 758→
 759→  // Always provide LocalAttachmentsContext so children get validated add function
 760→  return (
 761→    <LocalAttachmentsContext.Provider value={attachmentsCtx}>
 762→      {withReferencedSources}
 763→    </LocalAttachmentsContext.Provider>
 764→  );
 765→};
