 767→export type PromptInputBodyProps = HTMLAttributes<HTMLDivElement>;
 768→
 769→export const PromptInputBody = ({ className, ...props }: PromptInputBodyProps) => (
 770→  <div className={cn("contents", className)} {...props} />
 771→);
 772→
 773→export type PromptInputTextareaProps = ComponentProps<typeof InputGroupTextarea>;
 774→
 775→export const PromptInputTextarea = ({
 776→  onChange,
 777→  onKeyDown,
 778→  className,
 779→  placeholder = "What would you like to know?",
 780→  ...props
 781→}: PromptInputTextareaProps) => {
 782→  const controller = useOptionalPromptInputController();
 783→  const attachments = usePromptInputAttachments();
 784→  const [isComposing, setIsComposing] = useState(false);
 785→
 786→  const handleKeyDown: KeyboardEventHandler<HTMLTextAreaElement> = useCallback(
 787→    (e) => {
 788→      // Call the external onKeyDown handler first
 789→      onKeyDown?.(e);
 790→
 791→      // If the external handler prevented default, don't run internal logic
 792→      if (e.defaultPrevented) {
 793→        return;
 794→      }
 795→
 796→      if (e.key === "Enter") {
 797→        if (isComposing || e.nativeEvent.isComposing) {
 798→          return;
 799→        }
 800→        if (e.shiftKey) {
 801→          return;
 802→        }
 803→        e.preventDefault();
 804→
 805→        // Check if the submit button is disabled before submitting
 806→        const { form } = e.currentTarget;
 807→        const submitButton = form?.querySelector(
 808→          'button[type="submit"]',
 809→        ) as HTMLButtonElement | null;
 810→        if (submitButton?.disabled) {
 811→          return;
 812→        }
 813→
 814→        form?.requestSubmit();
 815→      }
 816→
 817→      // Remove last attachment when Backspace is pressed and textarea is empty
 818→      if (e.key === "Backspace" && e.currentTarget.value === "" && attachments.files.length > 0) {
 819→        e.preventDefault();
 820→        const lastAttachment = attachments.files.at(-1);
 821→        if (lastAttachment) {
 822→          attachments.remove(lastAttachment.id);
 823→        }
 824→      }
 825→    },
 826→    [onKeyDown, isComposing, attachments],
 827→  );
 828→
 829→  const handlePaste: ClipboardEventHandler<HTMLTextAreaElement> = useCallback(
 830→    (event) => {
 831→      const items = event.clipboardData?.items;
 832→
 833→      if (!items) {
 834→        return;
 835→      }
 836→
 837→      const files: File[] = [];
 838→
 839→      for (const item of items) {
 840→        if (item.kind === "file") {
 841→          const file = item.getAsFile();
 842→          if (file) {
 843→            files.push(file);
 844→          }
 845→        }
 846→      }
 847→
 848→      if (files.length > 0) {
 849→        event.preventDefault();
 850→        attachments.add(files);
 851→      }
 852→    },
 853→    [attachments],
 854→  );
 855→
 856→  const handleCompositionEnd = useCallback(() => setIsComposing(false), []);
 857→  const handleCompositionStart = useCallback(() => setIsComposing(true), []);
 858→
 859→  const controlledProps = controller
 860→    ? {
 861→        onChange: (e: ChangeEvent<HTMLTextAreaElement>) => {
 862→          controller.textInput.setInput(e.currentTarget.value);
 863→          onChange?.(e);
 864→        },
 865→        value: controller.textInput.value,
 866→      }
 867→    : {
 868→        onChange,
 869→      };
 870→
