 14→export function CvUploadSidebar() {
 15→  const [open, setOpen] = useState(false);
 16→  const [isDragging, setIsDragging] = useState(false);
 17→  const [file, setFile] = useState<File | null>(null);
 18→  const [uploading, setUploading] = useState(false);
