 17→/** Haal de widget_config token op uit de Flextender pagina HTML */
 18→async function fetchWidgetConfig(): Promise<string | null> {
 19→  const res = await fetch(PAGE_URL, { signal: AbortSignal.timeout(15_000) });
 20→  if (!res.ok) throw new Error(`Pagina laden mislukt: ${res.status}`);
 21→  const html = await res.text();
 22→  const match = html.match(/name="kbs_flx_widget_config"\s+value="([^"]+)"/);
 23→  return match?.[1] ?? null;
 24→}
