 26→export async function scrapeFlextender(): Promise<RawScrapedListing[]> {
 27→  console.log("Flextender scrapen via AJAX API (two-step met widget_config)");
 28→
 29→  const MAX_RETRIES = 2;
 30→  let attempt = 0;
 31→
 32→  while (attempt <= MAX_RETRIES) {
 33→    try {
 34→      // Stap 1: Haal widget_config token op uit de pagina
 35→      const widgetConfig = await fetchWidgetConfig();
 36→      if (!widgetConfig) {
 37→        console.warn("Flextender: widget_config niet gevonden op pagina, fallback zonder config");
 38→      }
 39→
 40→      // Stap 2: POST als multipart/form-data met widget_config
 41→      const formData = new FormData();
 42→      if (widgetConfig) {
 43→        formData.append("kbs_flx_widget_config", widgetConfig);
 44→      }
 45→      formData.append("action", "kbs_flx_searchjobs");
 46→      formData.append("kbs_flx_joblsrc_freetext", "");
 47→      formData.append("StackOverflow1370021", "Fix autosubmit bug");
 48→
 49→      const res = await fetch(AJAX_URL, {
 50→        method: "POST",
 51→        body: formData,
 52→        signal: AbortSignal.timeout(30_000),
 53→      });
 54→
 55→      if (!res.ok) {
 56→        throw new Error(`AJAX ${res.status}: ${res.statusText}`);
 57→      }
 58→
 59→      const data = await res.json();
 60→      const html: string = data.resultHtml ?? "";
 61→
 62→      if (!html) {
 63→        throw new Error("Flextender: lege HTML response van AJAX endpoint");
 64→      }
 65→
 66→      const listings = parseFlextenderHtml(html);
 67→      console.log(`Flextender: ${listings.length} opdrachten geparsed uit listings`);
 68→
 69→      const enriched = await enrichListings(listings);
 70→      console.log(`Flextender: ${enriched.length} opdrachten verrijkt met detail-pagina`);
 71→
 72→      return enriched;
 73→    } catch (err) {
 74→      attempt++;
 75→      if (attempt > MAX_RETRIES) {
 76→        throw new Error(
 77→          `Flextender scrape mislukt na ${MAX_RETRIES + 1} pogingen: ${err instanceof Error ? err.message : String(err)}`,
 78→        );
 79→      } else {
 80→        const delay = 1200 * 2 ** attempt + Math.floor(Math.random() * 500);
 81→        console.warn(`Flextender poging ${attempt} mislukt, retry in ${delay}ms: ${err}`);
 82→        await new Promise((r) => setTimeout(r, delay));
 83→      }
 84→    }
 85→  }
 86→
 87→  // Unreachable — while loop always returns or throws — but satisfies TypeScript
 88→  throw new Error("Flextender scrape: onverwacht einde van retry-loop");
 89→}
