106→
107→    const companyMatch = cardHtml.match(/class="css-customer">([^<]+)/);
108→    const company = companyMatch?.[1]?.trim();
109→
110→    // Extract aanvraagnr from URL params or path
111→    const aanvraagMatch = detailPath.match(/aanvraagnr=(\d+)/) ?? detailPath.match(/\/(\d+)$/);
112→    const externalId = aanvraagMatch?.[1] || `flx-${listings.length}`;
113→    if (!externalId) continue;
114→
115→    // Build proper external URL from original detail path
116→    const externalUrl = detailPath.startsWith("http")
117→      ? detailPath
118→      : `https://www.flextender.nl${detailPath.startsWith("/") ? "" : "/"}${detailPath}`;
