184→}
185→
186→// ── Detail-pagina verrijking ──────────────────────────────────────
187→
188→/** Verrijk listings met content van hun detail-pagina's (parallel, max 5 tegelijk) */
189→async function enrichListings(
190→  listings: FlextenderListing[],
191→  logger?: { info: (m: string) => void; warn: (m: string) => void },
192→): Promise<RawScrapedListing[]> {
193→  const CONCURRENCY = 5;
194→  const results: RawScrapedListing[] = [];
195→  let detailFailures = 0;
196→
197→  for (let i = 0; i < listings.length; i += CONCURRENCY) {
198→    const batch = listings.slice(i, i + CONCURRENCY);
199→    const enrichedBatch = await Promise.all(
200→      batch.map(async (listing) => {
201→        try {
202→          const detail = await fetchDetailPage(listing.externalId);
203→          if (
204→            listing._rawHours &&
205→            !detail.conditions?.some((condition) => condition.includes("Uren per week"))
206→          ) {
207→            detail.conditions = [
208→              ...(detail.conditions ?? []),
209→              `Uren per week: ${listing._rawHours}`,
210→            ];
211→          }
212→          const { _rawHours, ...listingClean } = listing;
213→          const merged = { ...listingClean, ...detail };
214→          // #region agent log
215→          if (
216→            (merged as { hoursPerWeek?: number }).hoursPerWeek === 0 ||
217→            (merged as { minHoursPerWeek?: number }).minHoursPerWeek === 0
218→          ) {
219→            fetch("http://127.0.0.1:7696/ingest/807648ac-0e4a-43e7-9281-fc9626035545", {
220→              method: "POST",
221→              headers: { "Content-Type": "application/json", "X-Debug-Session-Id": "df9709" },
222→              body: JSON.stringify({
223→                sessionId: "df9709",
224→                hypothesisId: "H5",
225→                location: "flextender.ts:enrich-merged",
226→                message: "merged listing has hoursPerWeek or minHoursPerWeek 0",
227→                data: {
228→                  externalId: merged.externalId,
229→                  hoursPerWeek: (merged as { hoursPerWeek?: number }).hoursPerWeek,
230→                  minHoursPerWeek: (merged as { minHoursPerWeek?: number }).minHoursPerWeek,
231→                },
232→                timestamp: Date.now(),
233→              }),
234→            }).catch(() => {});
235→          }
236→          // #endregion
237→          return merged;
238→        } catch (err) {
239→          detailFailures++;
240→          (logger?.warn ?? console.warn)(
241→            `Detail ophalen mislukt voor ${listing.externalId}: ${err}`,
242→          );
243→          // Return listing without detail enrichment — still usable
244→          const { _rawHours, ...listingClean } = listing;
245→          return listingClean;
246→        }
247→      }),
248→    );
249→    results.push(...enrichedBatch);
250→
251→    // Back-off between batches to avoid overwhelming Flextender
252→    if (i + CONCURRENCY < listings.length) {
253→      await new Promise((r) => setTimeout(r, 500));
254→    }
255→  }
256→
257→  if (detailFailures > 0) {
258→    const log = logger?.warn ?? console.warn;
259→    log(
260→      `Flextender: ${detailFailures}/${listings.length} detail-pagina's mislukt (${Math.round((1 - detailFailures / listings.length) * 100)}% verrijkt)`,
261→    );
262→  }
263→
264→  return results;
265→}
