267→/** Haal detail-pagina op en parse gestructureerde secties */
268→async function fetchDetailPage(aanvraagnr: string): Promise<FlextenderDetail> {
269→  const url = `${DETAIL_BASE}${aanvraagnr}`;
270→  const res = await fetch(url, { signal: AbortSignal.timeout(10_000) });
271→  if (!res.ok) throw new Error(`Detail ${res.status}: ${res.statusText}`);
272→
273→  const html = await res.text();
274→  return parseDetailHtml(html);
275→}
276→
277→/** Parse detail-pagina HTML naar gestructureerde velden */
278→function parseDetailHtml(html: string): FlextenderDetail {
279→  const result: FlextenderDetail = {};
280→
281→  const descMatch = html.match(
282→    /class="css-formattedjobdescription">([\s\S]*?)(?:<\/div>\s*<div\s+(?:style|class="css-navigation))/,
283→  );
284→  if (!descMatch) return result;
285→
286→  const content = descMatch[1];
287→
288→  const sections = extractSections(content);
289→
290→  const findSection = (needle: string): string | undefined => {
291→    const key = Object.keys(sections).find((k) => k.toLowerCase().includes(needle.toLowerCase()));
292→    return key ? sections[key] : undefined;
293→  };
294→
295→  const descParts: string[] = [];
296→  for (const key of ["Opdracht", "Organisatietekst", "Opdrachtgever"]) {
297→    if (sections[key]) descParts.push(sections[key]);
298→  }
299→  if (descParts.length > 0) {
300→    result.description = decodeEntities(descParts.join("\n\n")).substring(0, 8000);
301→  }
302→
303→  const reqText = findSection("vereisten") ?? findSection("knock-out");
304→  if (reqText) {
305→    result.requirements = parseNumberedList(reqText).map((item) => ({
306→      description: item,
307→      isKnockout: true,
308→    }));
309→  }
310→
311→  const selText = findSection("selectiecriteria");
312→  if (selText) {
313→    result.wishes = parseNumberedList(selText).map((item) => ({
314→      description: item,
315→    }));
316→  }
317→
318→  const compText = findSection("competenties");
319→  if (compText) {
320→    result.competences = parseBulletList(compText);
321→  }
322→
323→  const conditions: string[] = [];
324→
325→  const funcText = findSection("functieschaal");
326→  if (funcText) {
327→    const scaleMatch = funcText.match(/schaal\s*(\d+)/i);
328→    if (scaleMatch) conditions.push(`Functieschaal ${scaleMatch[1]}`);
329→  }
330→
331→  const feeText = findSection("fee");
332→  if (feeText) conditions.push(`Fee: ${feeText.trim()}`);
333→
334→  const werkText = findSection("werkdagen");
335→  if (werkText) conditions.push(`Werkdagen: ${werkText.trim()}`);
336→
337→  const cvText = findSection("cv-eisen");
338→  if (cvText) conditions.push(`CV-eisen: ${cvText.trim()}`);
339→
340→  // === Extract workArrangement from Werkdagen section ===
341→  if (werkText) {
342→    const lower = werkText.toLowerCase();
343→    if (
344→      lower.includes("hybride") ||
345→      lower.includes("in overleg") ||
346→      lower.includes("onderlinge afstemming")
347→    ) {
348→      result.workArrangement = "hybride";
349→    } else if (lower.includes("remote") || lower.includes("thuiswerk")) {
350→      result.workArrangement = "remote";
351→    } else {
352→      result.workArrangement = "op_locatie";
353→    }
354→  }
355→
356→  // === Extract positionsAvailable from "Benodigd aantal professionals" ===
357→  const profText = findSection("benodigd aantal");
358→  if (profText) {
359→    const numMatch = profText.match(/(\d+)/);
360→    if (numMatch) result.positionsAvailable = parseInt(numMatch[1], 10);
361→  }
362→
363→  // === Parse summary fields for structured data + conditions ===
364→  const summaryHtml =
365→    extractBetween(
366→      html,
367→      'class="css-summarybackground">',
368→      'class="css-formattedjobdescription">',
369→    ) ?? "";
370→  const summaryFields = parseFieldPairs(summaryHtml);
371→
372→  // extensionPossible from "Opties verlenging"
373→  const extensionRaw = summaryFields["Opties verlenging"];
374→  if (extensionRaw) {
375→    const lower = extensionRaw.toLowerCase();
376→    if (lower.includes("niet") || lower === "nee" || lower === "geen") {
377→      result.extensionPossible = false;
378→    } else {
379→      result.extensionPossible = true;
380→    }
381→  }
382→
383→  // hoursPerWeek from summary (may override listing-level if detail has it)
384→  const summaryHours = parseHoursPerWeek(summaryFields["Uren per week"]);
385→  // #region agent log
386→  if (
387→    summaryHours.hoursPerWeek === 0 ||
388→    summaryHours.minHoursPerWeek === 0 ||
389→    (summaryHours.hoursPerWeek !== undefined && summaryHours.hoursPerWeek <= 0)
390→  ) {
391→    fetch("http://127.0.0.1:7696/ingest/807648ac-0e4a-43e7-9281-fc9626035545", {
392→      method: "POST",
393→      headers: { "Content-Type": "application/json", "X-Debug-Session-Id": "df9709" },
394→      body: JSON.stringify({
395→        sessionId: "df9709",
396→        hypothesisId: "H2",
397→        location: "flextender.ts:detail-summary-hours",
398→        message: "detail summaryHours has 0 or non-positive",
399→        data: {
400→          rawUrenPerWeek: summaryFields["Uren per week"],
401→          summaryHours,
402→        },
403→        timestamp: Date.now(),
404→      }),
405→    }).catch(() => {});
406→  }
407→  // #endregion
408→  if (summaryHours.hoursPerWeek) {
409→    result.hoursPerWeek = summaryHours.hoursPerWeek;
410→    if (summaryHours.minHoursPerWeek) result.minHoursPerWeek = summaryHours.minHoursPerWeek;
411→  }
412→
413→  // educationLevel from summary "Opleidingsniveau"
414→  if (summaryFields.Opleidingsniveau) {
415→    result.educationLevel = summaryFields.Opleidingsniveau;
416→  }
417→
418→  // durationMonths from summary "Duur"
419→  if (summaryFields.Duur) {
420→    const dm = parseDurationMonths(summaryFields.Duur);
421→    if (dm) result.durationMonths = dm;
422→  }
423→
424→  // Remaining summary fields → conditions (keep existing behavior)
425→  const skipKeys = new Set([
426→    "Start",
427→    "Regio",
428→    "Einde inschrijfdatum",
429→    "Uren per week",
430→    "Opties verlenging",
431→    "Opleidingsniveau",
432→    "Duur",
433→  ]);
434→  for (const [key, value] of Object.entries(summaryFields)) {
435→    if (!value || skipKeys.has(key)) continue;
436→    conditions.push(`${key}: ${value}`);
437→  }
438→
439→  if (conditions.length > 0) {
440→    result.conditions = conditions.map(decodeEntities);
441→  }
442→
443→  // Always set countryCode for Flextender (Dutch government platform)
444→  result.countryCode = "NL";
445→
446→  return result;
447→}
