449→/** Extract text between two markers in HTML */
450→function extractBetween(html: string, start: string, end: string): string | null {
451→  const startIdx = html.indexOf(start);
452→  if (startIdx === -1) return null;
453→  const endIdx = html.indexOf(end, startIdx + start.length);
454→  if (endIdx === -1) return null;
455→  return html.substring(startIdx + start.length, endIdx);
456→}
457→
458→/** Splits HTML content op <strong> secties, retourneert header→body map */
459→function extractSections(html: string): Record<string, string> {
460→  const sections: Record<string, string> = {};
461→  const parts = html.split(/<(?:strong|b)>/i);
462→
463→  for (let i = 1; i < parts.length; i++) {
464→    const closeIdx = parts[i].search(/<\/(?:strong|b)>/i);
465→    if (closeIdx === -1) continue;
466→
467→    const header = stripHtml(parts[i].substring(0, closeIdx)).trim();
468→    const body = stripHtml(parts[i].substring(closeIdx)).trim();
469→
470→    if (header && body && header.length < 100) {
471→      sections[header] = body;
472→    }
473→  }
474→  return sections;
475→}
476→
477→/** Parse genummerde lijst (1. item; 2. item) naar string array */
478→function parseNumberedList(text: string): string[] {
479→  const items = text.split(/\n/).filter((l) => l.trim());
480→  const result: string[] = [];
481→  for (const line of items) {
482→    const cleaned = line.replace(/^\d+[.)]\s*/, "").trim();
483→    if (cleaned.length > 5) result.push(cleaned);
484→  }
485→  if (result.length === 0) {
486→    return text
487→      .split(/[;\n]/)
488→      .map((s) => s.replace(/^\d+[.)]\s*/, "").trim())
489→      .filter((s) => s.length > 5);
490→  }
491→  return result;
492→}
493→
494→/** Parse bullet list (- item; - item) naar string array */
495→function parseBulletList(text: string): string[] {
496→  return text
497→    .split(/[;\n]/)
498→    .map((s) => s.replace(/^[-•–]\s*/, "").trim())
499→    .filter((s) => s.length > 2);
500→}
501→
502→/** Decode common HTML entities in a string */
503→function decodeEntities(s: string): string {
504→  return s
505→    .replace(/&euro;/gi, "€")
506→    .replace(/&rsquo;/gi, "\u2019")
507→    .replace(/&lsquo;/gi, "\u2018")
508→    .replace(/&rdquo;/gi, "\u201D")
509→    .replace(/&ldquo;/gi, "\u201C")
510→    .replace(/&eacute;/gi, "é")
511→    .replace(/&euml;/gi, "ë")
512→    .replace(/&uuml;/gi, "ü")
513→    .replace(/&iuml;/gi, "ï")
514→    .replace(/&ouml;/gi, "ö")
515→    .replace(/&auml;/gi, "ä")
516→    .replace(/&nbsp;/gi, " ")
517→    .replace(/&amp;/gi, "&")
518→    .replace(/&lt;/gi, "<")
519→    .replace(/&gt;/gi, ">")
520→    .replace(/&quot;/gi, '"')
521→    .replace(/&#39;/gi, "'")
522→    .replace(/&#\d+;/g, (m) => String.fromCharCode(Number(m.slice(2, -1))));
523→}
524→
525→/** Parse alle caption-value paren uit een card HTML */
526→function parseFieldPairs(cardHtml: string): Record<string, string> {
527→  const fields: Record<string, string> = {};
528→  const pairRegex = /class="css-caption">([^<]+)<[\s\S]*?class="css-value">([^<]+)</gi;
529→  let pairMatch = pairRegex.exec(cardHtml);
530→  while (pairMatch !== null) {
531→    const key = pairMatch[1].trim();
532→    const value = pairMatch[2].trim();
533→    if (!fields[key]) fields[key] = value;
534→    pairMatch = pairRegex.exec(cardHtml);
535→  }
536→  return fields;
537→}
