539→/** Parse Nederlandse datum (bijv. "16 maart 2026") naar Date of undefined */
540→function parseDutchDate(raw: string | undefined): Date | undefined {
541→  if (!raw) return undefined;
542→  const s = raw.trim();
543→  if (s === "Z.s.m." || s.includes("uur") || s.length < 6) return undefined;
544→
545→  const months: Record<string, string> = {
546→    januari: "01",
547→    februari: "02",
548→    maart: "03",
549→    april: "04",
550→    mei: "05",
551→    juni: "06",
552→    juli: "07",
553→    augustus: "08",
554→    september: "09",
555→    oktober: "10",
556→    november: "11",
557→    december: "12",
558→  };
559→
560→  const match = s.match(/^(\d{1,2})\s+(\w+)\s+(\d{4})$/);
561→  if (match) {
562→    const month = months[match[2].toLowerCase()];
563→    if (month) {
564→      return new Date(`${match[3]}-${month}-${match[1].padStart(2, "0")}`);
565→    }
566→  }
567→
568→  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return new Date(s.slice(0, 10));
569→
570→  return undefined;
571→}
572→
573→/** Parse Dutch duration "6 maanden" → 6, "12 weken" → 3, "1 jaar" → 12 */
574→function parseDurationMonths(raw: string | undefined): number | undefined {
575→  if (!raw) return undefined;
576→  const lower = raw.toLowerCase().trim();
577→
578→  const maandenMatch = lower.match(/(\d+)\s*maand/);
579→  if (maandenMatch) return parseInt(maandenMatch[1], 10);
580→
581→  const wekenMatch = lower.match(/(\d+)\s*we[ek]/);
582→  if (wekenMatch) return Math.round(parseInt(wekenMatch[1], 10) / 4.33);
583→
584→  const jaarMatch = lower.match(/(\d+)\s*jaar/);
585→  if (jaarMatch) return parseInt(jaarMatch[1], 10) * 12;
586→
587→  return undefined;
588→}
589→
590→/** Parse "Uren per week" field: "36 uur" → {max:36}, "24 tot 32 uur" → {min:24, max:32} */
591→function parseHoursPerWeek(raw: string | undefined): {
592→  hoursPerWeek?: number;
593→  minHoursPerWeek?: number;
594→} {
595→  if (!raw) return {};
596→  const rangeMatch = raw.match(/(\d+)\s*tot\s*(\d+)/);
597→  if (rangeMatch) {
598→    const min = parseInt(rangeMatch[1], 10);
599→    const max = parseInt(rangeMatch[2], 10);
600→    return {
601→      minHoursPerWeek: min > 0 ? min : undefined,
602→      hoursPerWeek: max > 0 ? max : undefined,
603→    };
604→  }
605→  const singleMatch = raw.match(/(\d+)/);
606→  if (singleMatch) {
607→    const hours = parseInt(singleMatch[1], 10);
608→    return hours > 0 ? { hoursPerWeek: hours } : {};
609→  }
610→  return {};
611→}
612→
613→/** Map regio/locatie naar Nederlandse provincie */
614→function extractProvince(location: string | undefined): string | undefined {
615→  if (!location) return undefined;
616→  const loc = location.toLowerCase();
617→
618→  const provinces: Record<string, string> = {
619→    "noord-holland": "Noord-Holland",
620→    "zuid-holland": "Zuid-Holland",
621→    "noord-brabant": "Noord-Brabant",
622→    utrecht: "Utrecht",
623→    gelderland: "Gelderland",
624→    overijssel: "Overijssel",
625→    limburg: "Limburg",
626→    friesland: "Friesland",
627→    groningen: "Groningen",
628→    drenthe: "Drenthe",
629→    flevoland: "Flevoland",
630→    zeeland: "Zeeland",
631→  };
632→
633→  for (const [key, value] of Object.entries(provinces)) {
634→    if (loc.includes(key)) return value;
635→  }
636→  return undefined;
637→}
