 10→
 11→// ========== Helpers ==========
 12→
 13→function cronIntervalMs(expr: string | null | undefined): number {
 14→  const HOUR = 3_600_000;
 15→  if (!expr) return 24 * HOUR;
 16→
 17→  const parts = expr.trim().split(/\s+/);
 18→  const fields = parts.length === 6 ? parts.slice(1) : parts;
 19→  if (fields.length < 5) return 24 * HOUR;
 20→
 21→  const [minute, hour] = fields;
 22→
 23→  const hourStep = hour.match(/^\*\/(\d+)$/);
 24→  if (hourStep) return Number(hourStep[1]) * HOUR;
 25→
 26→  const minStep = minute.match(/^\*\/(\d+)$/);
 27→  if (minStep) return Number(minStep[1]) * 60_000;
 28→
 29→  if (/^\d+$/.test(hour) && /^\d+$/.test(minute)) return 24 * HOUR;
 30→
 31→  return 24 * HOUR;
 32→}
 33→
 34→function isDue(
 35→  cronExpression: string | null | undefined,
 36→  lastRunAt: Date | null | undefined,
 37→): boolean {
 38→  if (!lastRunAt) return true;
 39→  const interval = cronIntervalMs(cronExpression);
 40→  const grace = 5 * 60_000;
 41→  return Date.now() - lastRunAt.getTime() >= interval - grace;
 42→}
 43→
 44→// ========== Scheduled Task ==========
 45→
 46→export const scrapePipelineTask = schedules.task({
 47→  id: "scrape-pipeline",
 48→  cron: {
 49→    pattern: "0 */4 * * *", // Every 4 hours
 50→    timezone: "Europe/Amsterdam",
 51→  },
 52→  maxDuration: 600, // 10 minutes max
 53→  run: async () => {
 54→    const activeConfigs = await db
 55→      .select()
 56→      .from(scraperConfigs)
 57→      .where(eq(scraperConfigs.isActive, true));
 58→
 59→    if (activeConfigs.length === 0) {
 60→      logger.info("Geen actieve scraper configs");
 61→      return { dispatched: 0, results: [] };
 62→    }
 63→
 64→    let dispatched = 0;
 65→    let tripped = 0;
 66→    let skippedSchedule = 0;
 67→    const results: Record<string, unknown>[] = [];
 68→
 69→    // Filter: circuit breaker + schedule check
 70→    const eligible = activeConfigs.filter((cfg) => {
 71→      if ((cfg.consecutiveFailures ?? 0) >= CIRCUIT_BREAKER_THRESHOLD) {
 72→        tripped++;
 73→        publish("scrape:circuit_breaker_open", {
 74→          platform: cfg.platform,
 75→          consecutiveFailures: cfg.consecutiveFailures ?? 0,
 76→          threshold: CIRCUIT_BREAKER_THRESHOLD,
 77→          source: "trigger.dev",
 78→        });
 79→        logger.warn(`Circuit breaker open for ${cfg.platform}`, {
 80→          consecutiveFailures: cfg.consecutiveFailures,
 81→        });
 82→        trackServerEvent("system", "scrape_circuit_breaker_open", {
 83→          platform: cfg.platform,
 84→          consecutiveFailures: cfg.consecutiveFailures ?? 0,
 85→          threshold: CIRCUIT_BREAKER_THRESHOLD,
 86→        });
 87→        results.push({ platform: cfg.platform, status: "circuit_breaker_open" });
 88→        return false;
 89→      }
 90→
 91→      if (!isDue(cfg.cronExpression, cfg.lastRunAt)) {
 92→        skippedSchedule++;
 93→        results.push({ platform: cfg.platform, status: "not_due" });
 94→        return false;
 95→      }
 96→
 97→      return true;
 98→    });
 99→
100→    // Run all eligible scrapers in parallel
101→    const settled = await Promise.allSettled(
102→      eligible.map((cfg) => runScrapePipeline(cfg.platform, cfg.baseUrl)),
103→    );
104→
105→    for (let i = 0; i < eligible.length; i++) {
106→      const r = settled[i];
107→      dispatched++;
108→      const platform = eligible[i].platform;
109→      if (r.status === "fulfilled") {
110→        const scrapeData = { platform, status: "success", ...r.value };
111→        results.push(scrapeData);
112→        notifySlack("scrape:complete", scrapeData);
113→        trackServerEvent("system", "scrape_completed", {
114→          platform,
115→          ...r.value,
116→        });
117→      } else {
118→        results.push({ platform, status: "failed", error: String(r.reason) });
119→        notifySlack("scrape:complete", {
120→          platform,
121→          status: "failed",
122→          jobsFound: 0,
123→          jobsNew: 0,
124→          duplicates: 0,
125→          durationMs: 0,
126→        });
127→        trackServerEvent("system", "scrape_failed", {
128→          platform,
129→          error: String(r.reason),
130→        });
131→      }
132→    }
133→
134→    if (tripped > 0) {
135→      publish("scrape:alert", {
136→        severity: "warning",
137→        type: "circuit_breaker_open",
138→        tripped,
139→      });
140→      notifySlack("scrape:alert", {
141→        severity: "warning",
142→        type: "circuit_breaker_open",
143→        tripped: activeConfigs
144→          .filter((cfg) => (cfg.consecutiveFailures ?? 0) >= CIRCUIT_BREAKER_THRESHOLD)
145→          .map((cfg) => cfg.platform),
146→      });
147→      trackServerEvent("system", "scrape_circuit_breaker", { tripped });
148→    }
149→
150→    logger.info("Scrape pipeline voltooid", {
151→      dispatched,
152→      tripped,
153→      skippedSchedule,
154→    });
155→    trackServerEvent("system", "scrape_pipeline_completed", {
156→      dispatched,
157→      tripped,
158→      skippedSchedule,
159→    });
160→
161→    return { dispatched, tripped, skippedSchedule, results };
162→  },
163→});
