  1→import { stripHtml } from "../../lib/html";
  2→import type { RawScrapedListing } from "../normalize";
  3→
  4→const PAGE_URL = "https://www.flextender.nl/opdrachten/";
  5→const AJAX_URL = "https://www.flextender.nl/wp-admin/admin-ajax.php";
  6→const DETAIL_BASE = "https://www.flextender.nl/opdracht/?aanvraagnr=";
  7→
  8→type FlextenderListing = RawScrapedListing & {
  9→  externalId: string;
 10→  _rawHours?: string;
 11→};
