 13→type FlextenderDetail = Partial<RawScrapedListing> & {
 14→  conditions?: string[];
 15→};
 16→
 17→/** Haal de widget_config token op uit de Flextender pagina HTML */
 18→async function fetchWidgetConfig(): Promise<string | null> {
 19→  const res = await fetch(PAGE_URL, { signal: AbortSignal.timeout(15_000) });
 20→  if (!res.ok) throw new Error(`Pagina laden mislukt: ${res.status}`);
 21→  const html = await res.text();
 22→  const match = html.match(/name="kbs_flx_widget_config"\s+value="([^"]+)"/);
 23→  return match?.[1] ?? null;
 24→}
 25→
 26→export async function scrapeFlextender(): Promise<RawScrapedListing[]> {
 27→  console.log("Flextender scrapen via AJAX API (two-step met widget_config)");
 28→
 29→  const MAX_RETRIES = 2;
 30→  let attempt = 0;
 31→
 32→  while (attempt <= MAX_RETRIES) {
 33→    try {
 34→      // Stap 1: Haal widget_config token op uit de pagina
 35→      const widgetConfig = await fetchWidgetConfig();
 36→      if (!widgetConfig) {
 37→        console.warn("Flextender: widget_config niet gevonden op pagina, fallback zonder config");
 38→      }
 39→
 40→      // Stap 2: POST als multipart/form-data met widget_config
 41→      const formData = new FormData();
 42→      if (widgetConfig) {
 43→        formData.append("kbs_flx_widget_config", widgetConfig);
 44→      }
 45→      formData.append("action", "kbs_flx_searchjobs");
 46→      formData.append("kbs_flx_joblsrc_freetext", "");
 47→      formData.append("StackOverflow1370021", "Fix autosubmit bug");
 48→
 49→      const res = await fetch(AJAX_URL, {
 50→        method: "POST",
 51→        body: formData,
 52→        signal: AbortSignal.timeout(30_000),
 53→      });
 54→
 55→      if (!res.ok) {
 56→        throw new Error(`AJAX ${res.status}: ${res.statusText}`);
 57→      }
 58→
 59→      const data = await res.json();
 60→      const html: string = data.resultHtml ?? "";
 61→
 62→      if (!html) {
 63→        throw new Error("Flextender: lege HTML response van AJAX endpoint");
 64→      }
 65→
 66→      const listings = parseFlextenderHtml(html);
 67→      console.log(`Flextender: ${listings.length} opdrachten geparsed uit listings`);
 68→
 69→      const enriched = await enrichListings(listings);
 70→      console.log(`Flextender: ${enriched.length} opdrachten verrijkt met detail-pagina`);
 71→
 72→      return enriched;
 73→    } catch (err) {
 74→      attempt++;
 75→      if (attempt > MAX_RETRIES) {
 76→        throw new Error(
 77→          `Flextender scrape mislukt na ${MAX_RETRIES + 1} pogingen: ${err instanceof Error ? err.message : String(err)}`,
 78→        );
 79→      } else {
 80→        const delay = 1200 * 2 ** attempt + Math.floor(Math.random() * 500);
 81→        console.warn(`Flextender poging ${attempt} mislukt, retry in ${delay}ms: ${err}`);
 82→        await new Promise((r) => setTimeout(r, delay));
 83→      }
 84→    }
 85→  }
 86→
 87→  // Unreachable — while loop always returns or throws — but satisfies TypeScript
 88→  throw new Error("Flextender scrape: onverwacht einde van retry-loop");
 89→}
 90→
 91→/** Parse Flextender AJAX HTML response naar listing array */
 92→function parseFlextenderHtml(html: string): FlextenderListing[] {
 93→  const listings: FlextenderListing[] = [];
 94→
 95→  const cardRegex =
 96→    /<div\s+class="css-foundjob[^"]*"\s+data-kbslinkurl="([^"]*)"[^>]*>([\s\S]*?)(?=<div\s+class="css-foundjob|<div\s+class="flx-register-panel|$)/gi;
 97→
 98→  let cardMatch = cardRegex.exec(html);
 99→  while (cardMatch !== null) {
100→    const detailPath = cardMatch[1];
101→    const cardHtml = cardMatch[2];
102→
103→    const titleMatch = cardHtml.match(/class="css-jobtitle">([^<]+)/);
104→    const title = titleMatch?.[1]?.trim();
105→    if (!title) continue;
106→
107→    const companyMatch = cardHtml.match(/class="css-customer">([^<]+)/);
108→    const company = companyMatch?.[1]?.trim();
109→
110→    // Extract aanvraagnr from URL params or path
111→    const aanvraagMatch = detailPath.match(/aanvraagnr=(\d+)/) ?? detailPath.match(/\/(\d+)$/);
112→    const externalId = aanvraagMatch?.[1] || `flx-${listings.length}`;
113→    if (!externalId) continue;
114→
115→    // Build proper external URL from original detail path
116→    const externalUrl = detailPath.startsWith("http")
117→      ? detailPath
118→      : `https://www.flextender.nl${detailPath.startsWith("/") ? "" : "/"}${detailPath}`;
119→
120→    const fields = parseFieldPairs(cardHtml);
121→
122→    const province = extractProvince(fields.Regio);
123→    const location = fields.Regio ?? undefined;
124→
125→    // Parse "Uren per week": "36 uur" → 36, "24 tot 32 uur" → min=24, max=32
126→    const { hoursPerWeek, minHoursPerWeek } = parseHoursPerWeek(fields["Uren per week"]);
127→    // #region agent log
128→    if (hoursPerWeek === 0 || minHoursPerWeek === 0) {
129→      fetch("http://127.0.0.1:7696/ingest/807648ac-0e4a-43e7-9281-fc9626035545", {
130→        method: "POST",
131→        headers: { "Content-Type": "application/json", "X-Debug-Session-Id": "df9709" },
132→        body: JSON.stringify({
133→          sessionId: "df9709",
134→          hypothesisId: "H1",
135→          location: "flextender.ts:listing-hours",
136→          message: "listing hoursPerWeek or minHoursPerWeek is 0",
137→          data: {
138→            externalId,
139→            rawUrenPerWeek: fields["Uren per week"],
140→            hoursPerWeek,
141→            minHoursPerWeek,
142→          },
143→          timestamp: Date.now(),
144→        }),
145→      }).catch(() => {});
146→    }
147→    // #endregion
148→
149→    // Extract company logo URL
150→    const logoMatch =
151→      cardHtml.match(/class="flx-client-logo"[^>]*src="([^"]+)"/i) ??
152→      cardHtml.match(/src="([^"]+)"[^>]*class="flx-client-logo"/i);
153→    const companyLogoUrl = logoMatch?.[1] ?? undefined;
154→
155→    // Opleidingsniveau from listing card
156→    const educationLevel = fields.Opleidingsniveau ?? undefined;
157→
158→    // Duration from "Duur" field: "6 maanden" → 6
159→    const durationMonths = parseDurationMonths(fields.Duur);
160→
161→    listings.push({
162→      title,
163→      company,
164→      location,
165→      province,
166→      description: `${title} — ${company ?? "Flextender"} opdracht`,
167→      externalId,
168→      externalUrl,
169→      startDate: parseDutchDate(fields.Start),
170→      applicationDeadline: parseDutchDate(fields["Einde inschrijfdatum"]),
171→      contractType: "opdracht" as const,
172→      countryCode: "NL",
173→      hoursPerWeek,
174→      minHoursPerWeek,
175→      companyLogoUrl,
176→      educationLevel,
177→      durationMonths,
178→      _rawHours: fields["Uren per week"] ?? undefined, // kept for conditions fallback
179→    });
180→    cardMatch = cardRegex.exec(html);
181→  }
182→
183→  return listings;
184→}
185→
186→// ── Detail-pagina verrijking ──────────────────────────────────────
187→
188→/** Verrijk listings met content van hun detail-pagina's (parallel, max 5 tegelijk) */
189→async function enrichListings(
190→  listings: FlextenderListing[],
191→  logger?: { info: (m: string) => void; warn: (m: string) => void },
192→): Promise<RawScrapedListing[]> {
193→  const CONCURRENCY = 5;
194→  const results: RawScrapedListing[] = [];
195→  let detailFailures = 0;
196→
197→  for (let i = 0; i < listings.length; i += CONCURRENCY) {
198→    const batch = listings.slice(i, i + CONCURRENCY);
199→    const enrichedBatch = await Promise.all(
200→      batch.map(async (listing) => {
201→        try {
202→          const detail = await fetchDetailPage(listing.externalId);
203→          if (
204→            listing._rawHours &&
205→            !detail.conditions?.some((condition) => condition.includes("Uren per week"))
206→          ) {
