267→/** Haal detail-pagina op en parse gestructureerde secties */
268→async function fetchDetailPage(aanvraagnr: string): Promise<FlextenderDetail> {
269→  const url = `${DETAIL_BASE}${aanvraagnr}`;
270→  const res = await fetch(url, { signal: AbortSignal.timeout(10_000) });
271→  if (!res.ok) throw new Error(`Detail ${res.status}: ${res.statusText}`);
272→
273→  const html = await res.text();
274→  return parseDetailHtml(html);
275→}
276→
277→/** Parse detail-pagina HTML naar gestructureerde velden */
278→function parseDetailHtml(html: string): FlextenderDetail {
279→  const result: FlextenderDetail = {};
280→
281→  const descMatch = html.match(
282→    /class="css-formattedjobdescription">([\s\S]*?)(?:<\/div>\s*<div\s+(?:style|class="css-navigation))/,
283→  );
284→  if (!descMatch) return result;
285→
286→  const content = descMatch[1];
287→
288→  const sections = extractSections(content);
289→
290→  const findSection = (needle: string): string | undefined => {
291→    const key = Object.keys(sections).find((k) => k.toLowerCase().includes(needle.toLowerCase()));
292→    return key ? sections[key] : undefined;
293→  };
294→
295→  const descParts: string[] = [];
296→  for (const key of ["Opdracht", "Organisatietekst", "Opdrachtgever"]) {
297→    if (sections[key]) descParts.push(sections[key]);
298→  }
299→  if (descParts.length > 0) {
300→    result.description = decodeEntities(descParts.join("\n\n")).substring(0, 8000);
301→  }
302→
303→  const reqText = findSection("vereisten") ?? findSection("knock-out");
304→  if (reqText) {
305→    result.requirements = parseNumberedList(reqText).map((item) => ({
306→      description: item,
307→      isKnockout: true,
308→    }));
309→  }
310→
311→  const selText = findSection("selectiecriteria");
312→  if (selText) {
313→    result.wishes = parseNumberedList(selText).map((item) => ({
314→      description: item,
315→    }));
316→  }
317→
318→  const compText = findSection("competenties");
319→  if (compText) {
320→    result.competences = parseBulletList(compText);
321→  }
322→
323→  const conditions: string[] = [];
324→
325→  const funcText = findSection("functieschaal");
326→  if (funcText) {
327→    const scaleMatch = funcText.match(/schaal\s*(\d+)/i);
328→    if (scaleMatch) conditions.push(`Functieschaal ${scaleMatch[1]}`);
329→  }
330→
331→  const feeText = findSection("fee");
332→  if (feeText) conditions.push(`Fee: ${feeText.trim()}`);
333→
334→  const werkText = findSection("werkdagen");
335→  if (werkText) conditions.push(`Werkdagen: ${werkText.trim()}`);
336→
337→  const cvText = findSection("cv-eisen");
338→  if (cvText) conditions.push(`CV-eisen: ${cvText.trim()}`);
339→
340→  // === Extract workArrangement from Werkdagen section ===
341→  if (werkText) {
342→    const lower = werkText.toLowerCase();
343→    if (
344→      lower.includes("hybride") ||
345→      lower.includes("in overleg") ||
346→      lower.includes("onderlinge afstemming")
347→    ) {
348→      result.workArrangement = "hybride";
349→    } else if (lower.includes("remote") || lower.includes("thuiswerk")) {
350→      result.workArrangement = "remote";
351→    } else {
352→      result.workArrangement = "op_locatie";
353→    }
354→  }
355→
356→  // === Extract positionsAvailable from "Benodigd aantal professionals" ===
357→  const profText = findSection("benodigd aantal");
358→  if (profText) {
359→    const numMatch = profText.match(/(\d+)/);
360→    if (numMatch) result.positionsAvailable = parseInt(numMatch[1], 10);
361→  }
362→
363→  // === Parse summary fields for structured data + conditions ===
364→  const summaryHtml =
365→    extractBetween(
366→      html,
367→      'class="css-summarybackground">',
368→      'class="css-formattedjobdescription">',
369→    ) ?? "";
370→  const summaryFields = parseFieldPairs(summaryHtml);
371→
372→  // extensionPossible from "Opties verlenging"
373→  const extensionRaw = summaryFields["Opties verlenging"];
374→  if (extensionRaw) {
375→    const lower = extensionRaw.toLowerCase();
376→    if (lower.includes("niet") || lower === "nee" || lower === "geen") {
377→      result.extensionPossible = false;
378→    } else {
379→      result.extensionPossible = true;
380→    }
381→  }
382→
383→  // hoursPerWeek from summary (may override listing-level if detail has it)
384→  const summaryHours = parseHoursPerWeek(summaryFields["Uren per week"]);
385→  // #region agent log
386→  if (
387→    summaryHours.hoursPerWeek === 0 ||
388→    summaryHours.minHoursPerWeek === 0 ||
389→    (summaryHours.hoursPerWeek !== undefined && summaryHours.hoursPerWeek <= 0)
390→  ) {
391→    fetch("http://127.0.0.1:7696/ingest/807648ac-0e4a-43e7-9281-fc9626035545", {
392→      method: "POST",
393→      headers: { "Content-Type": "application/json", "X-Debug-Session-Id": "df9709" },
394→      body: JSON.stringify({
395→        sessionId: "df9709",
396→        hypothesisId: "H2",
397→        location: "flextender.ts:detail-summary-hours",
398→        message: "detail summaryHours has 0 or non-positive",
399→        data: {
400→          rawUrenPerWeek: summaryFields["Uren per week"],
401→          summaryHours,
402→        },
403→        timestamp: Date.now(),
404→      }),
405→    }).catch(() => {});
406→  }
407→  // #endregion
408→  if (summaryHours.hoursPerWeek) {
409→    result.hoursPerWeek = summaryHours.hoursPerWeek;
410→    if (summaryHours.minHoursPerWeek) result.minHoursPerWeek = summaryHours.minHoursPerWeek;
411→  }
412→
413→  // educationLevel from summary "Opleidingsniveau"
414→  if (summaryFields.Opleidingsniveau) {
415→    result.educationLevel = summaryFields.Opleidingsniveau;
416→  }
417→
418→  // durationMonths from summary "Duur"
419→  if (summaryFields.Duur) {
420→    const dm = parseDurationMonths(summaryFields.Duur);
421→    if (dm) result.durationMonths = dm;
422→  }
423→
424→  // Remaining summary fields → conditions (keep existing behavior)
425→  const skipKeys = new Set([
426→    "Start",
427→    "Regio",
428→    "Einde inschrijfdatum",
429→    "Uren per week",
430→    "Opties verlenging",
431→    "Opleidingsniveau",
432→    "Duur",
433→  ]);
434→  for (const [key, value] of Object.entries(summaryFields)) {
435→    if (!value || skipKeys.has(key)) continue;
436→    conditions.push(`${key}: ${value}`);
437→  }
438→
439→  if (conditions.length > 0) {
440→    result.conditions = conditions.map(decodeEntities);
441→  }
442→
443→  // Always set countryCode for Flextender (Dutch government platform)
444→  result.countryCode = "NL";
445→
446→  return result;
447→}
448→
449→/** Extract text between two markers in HTML */
450→function extractBetween(html: string, start: string, end: string): string | null {
451→  const startIdx = html.indexOf(start);
452→  if (startIdx === -1) return null;
453→  const endIdx = html.indexOf(end, startIdx + start.length);
454→  if (endIdx === -1) return null;
455→  return html.substring(startIdx + start.length, endIdx);
456→}
457→
458→/** Splits HTML content op <strong> secties, retourneert header→body map */
459→function extractSections(html: string): Record<string, string> {
460→  const sections: Record<string, string> = {};
461→  const parts = html.split(/<(?:strong|b)>/i);
462→
463→  for (let i = 1; i < parts.length; i++) {
464→    const closeIdx = parts[i].search(/<\/(?:strong|b)>/i);
465→    if (closeIdx === -1) continue;
466→
467→    const header = stripHtml(parts[i].substring(0, closeIdx)).trim();
468→    const body = stripHtml(parts[i].substring(closeIdx)).trim();
469→
470→    if (header && body && header.length < 100) {
471→      sections[header] = body;
472→    }
473→  }
474→  return sections;
475→}
476→
477→/** Parse genummerde lijst (1. item; 2. item) naar string array */
478→function parseNumberedList(text: string): string[] {
479→  const items = text.split(/\n/).filter((l) => l.trim());
480→  const result: string[] = [];
481→  for (const line of items) {
482→    const cleaned = line.replace(/^\d+[.)]\s*/, "").trim();
483→    if (cleaned.length > 5) result.push(cleaned);
484→  }
485→  if (result.length === 0) {
486→    return text
487→      .split(/[;\n]/)
488→      .map((s) => s.replace(/^\d+[.)]\s*/, "").trim())
489→      .filter((s) => s.length > 5);
490→  }
491→  return result;
492→}
493→
494→/** Parse bullet list (- item; - item) naar string array */
495→function parseBulletList(text: string): string[] {
496→  return text
497→    .split(/[;\n]/)
498→    .map((s) => s.replace(/^[-•–]\s*/, "").trim())
499→    .filter((s) => s.length > 2);
500→}
501→
502→/** Decode common HTML entities in a string */
503→function decodeEntities(s: string): string {
504→  return s
505→    .replace(/&euro;/gi, "€")
506→    .replace(/&rsquo;/gi, "\u2019")
507→    .replace(/&lsquo;/gi, "\u2018")
508→    .replace(/&rdquo;/gi, "\u201D")
509→    .replace(/&ldquo;/gi, "\u201C")
510→    .replace(/&eacute;/gi, "é")
511→    .replace(/&euml;/gi, "ë")
512→    .replace(/&uuml;/gi, "ü")
513→    .replace(/&iuml;/gi, "ï")
514→    .replace(/&ouml;/gi, "ö")
515→    .replace(/&auml;/gi, "ä")
516→    .replace(/&nbsp;/gi, " ")
517→    .replace(/&amp;/gi, "&")
518→    .replace(/&lt;/gi, "<")
519→    .replace(/&gt;/gi, ">")
520→    .replace(/&quot;/gi, '"')
521→    .replace(/&#39;/gi, "'")
522→    .replace(/&#\d+;/g, (m) => String.fromCharCode(Number(m.slice(2, -1))));
523→}
524→
525→/** Parse alle caption-value paren uit een card HTML */
526→function parseFieldPairs(cardHtml: string): Record<string, string> {
527→  const fields: Record<string, string> = {};
528→  const pairRegex = /class="css-caption">([^<]+)<[\s\S]*?class="css-value">([^<]+)</gi;
529→  let pairMatch = pairRegex.exec(cardHtml);
530→  while (pairMatch !== null) {
531→    const key = pairMatch[1].trim();
532→    const value = pairMatch[2].trim();
533→    if (!fields[key]) fields[key] = value;
534→    pairMatch = pairRegex.exec(cardHtml);
535→  }
536→  return fields;
537→}
538→
539→/** Parse Nederlandse datum (bijv. "16 maart 2026") naar Date of undefined */
540→function parseDutchDate(raw: string | undefined): Date | undefined {
541→  if (!raw) return undefined;
542→  const s = raw.trim();
543→  if (s === "Z.s.m." || s.includes("uur") || s.length < 6) return undefined;
544→
545→  const months: Record<string, string> = {
546→    januari: "01",
547→    februari: "02",
548→    maart: "03",
549→    april: "04",
550→    mei: "05",
551→    juni: "06",
552→    juli: "07",
553→    augustus: "08",
554→    september: "09",
555→    oktober: "10",
556→    november: "11",
557→    december: "12",
558→  };
559→
560→  const match = s.match(/^(\d{1,2})\s+(\w+)\s+(\d{4})$/);
561→  if (match) {
562→    const month = months[match[2].toLowerCase()];
563→    if (month) {
564→      return new Date(`${match[3]}-${month}-${match[1].padStart(2, "0")}`);
565→    }
566→  }
567→
568→  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return new Date(s.slice(0, 10));
569→
570→  return undefined;
571→}
572→
573→/** Parse Dutch duration "6 maanden" → 6, "12 weken" → 3, "1 jaar" → 12 */
574→function parseDurationMonths(raw: string | undefined): number | undefined {
575→  if (!raw) return undefined;
576→  const lower = raw.toLowerCase().trim();
577→
578→  const maandenMatch = lower.match(/(\d+)\s*maand/);
579→  if (maandenMatch) return parseInt(maandenMatch[1], 10);
580→
581→  const wekenMatch = lower.match(/(\d+)\s*we[ek]/);
582→  if (wekenMatch) return Math.round(parseInt(wekenMatch[1], 10) / 4.33);
583→
584→  const jaarMatch = lower.match(/(\d+)\s*jaar/);
585→  if (jaarMatch) return parseInt(jaarMatch[1], 10) * 12;
586→
587→  return undefined;
588→}
589→
590→/** Parse "Uren per week" field: "36 uur" → {max:36}, "24 tot 32 uur" → {min:24, max:32} */
591→function parseHoursPerWeek(raw: string | undefined): {
592→  hoursPerWeek?: number;
593→  minHoursPerWeek?: number;
594→} {
595→  if (!raw) return {};
596→  const rangeMatch = raw.match(/(\d+)\s*tot\s*(\d+)/);
597→  if (rangeMatch) {
598→    const min = parseInt(rangeMatch[1], 10);
599→    const max = parseInt(rangeMatch[2], 10);
600→    return {
601→      minHoursPerWeek: min > 0 ? min : undefined,
602→      hoursPerWeek: max > 0 ? max : undefined,
603→    };
604→  }
605→  const singleMatch = raw.match(/(\d+)/);
606→  if (singleMatch) {
607→    const hours = parseInt(singleMatch[1], 10);
608→    return hours > 0 ? { hoursPerWeek: hours } : {};
609→  }
610→  return {};
611→}
612→
613→/** Map regio/locatie naar Nederlandse provincie */
614→function extractProvince(location: string | undefined): string | undefined {
615→  if (!location) return undefined;
616→  const loc = location.toLowerCase();
617→
618→  const provinces: Record<string, string> = {
619→    "noord-holland": "Noord-Holland",
620→    "zuid-holland": "Zuid-Holland",
621→    "noord-brabant": "Noord-Brabant",
622→    utrecht: "Utrecht",
623→    gelderland: "Gelderland",
624→    overijssel: "Overijssel",
625→    limburg: "Limburg",
626→    friesland: "Friesland",
627→    groningen: "Groningen",
628→    drenthe: "Drenthe",
629→    flevoland: "Flevoland",
630→    zeeland: "Zeeland",
631→  };
632→
633→  for (const [key, value] of Object.entries(provinces)) {
634→    if (loc.includes(key)) return value;
635→  }
636→  return undefined;
637→}
