133→      .filter((c) => c.resumeParsedAt !== null)
134→      .map((c) => ({
135→        id: c.id,
136→        name: c.name,
137→        role: c.role,
138→        resumeUrl: c.resumeUrl,
139→        resumeParsedAt: c.resumeParsedAt as Date,
140→      }));
141→
142→    return (
143→      <div className="flex-1 overflow-y-auto">
144→        <div className="max-w-[1400px] mx-auto px-4 md:px-6 lg:px-8 py-6 space-y-6">
145→          <div>
146→            <h1 className="text-xl font-bold text-foreground">Matching</h1>
147→            <p className="text-sm text-muted-foreground mt-1">
148→              AI-gestuurde matching — beoordeel kandidaat-vacature matches
149→            </p>
150→          </div>
151→
152→          <FilterTabs
153→            options={tabOptions}
154→            activeValue={tab}
155→            buildHref={(v) => `/matching${buildQs(v ? { tab: v } : {}, jobId)}`}
156→            variant="subtle"
157→          />
158→
159→          <CvAnalyseTab recentAnalyses={recentCvs} />
160→        </div>
161→      </div>
162→    );
163→  }
164→
165→  // Build WHERE conditions: always filter by status, optionally by jobId
166→  const conditions: ReturnType<typeof eq>[] = [];
167→  if (statusFilter) conditions.push(eq(jobMatches.status, statusFilter));
168→  if (jobId) conditions.push(eq(jobMatches.jobId, jobId));
169→  const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
170→
171→  // Scoped count conditions (for KPI cards, scoped to jobId if present)
172→  const scopeCondition = jobId ? eq(jobMatches.jobId, jobId) : undefined;
173→
174→  const [matchRows, totalResult, statusCounts] = await Promise.all([
175→    db
176→      .select({
177→        match: jobMatches,
178→        job: { id: jobs.id, title: jobs.title, company: jobs.company },
179→        candidate: {
180→          id: candidates.id,
181→          name: candidates.name,
182→          role: candidates.role,
183→        },
184→      })
