186→      .leftJoin(jobs, eq(jobMatches.jobId, jobs.id))
187→      .leftJoin(candidates, eq(jobMatches.candidateId, candidates.id))
188→      .where(whereClause)
189→      .orderBy(desc(jobMatches.matchScore))
190→      .limit(PER_PAGE)
191→      .offset(offset),
192→    db.select({ count: sql<number>`count(*)::int` }).from(jobMatches).where(whereClause),
193→    db
