195→        pending: sql<number>`count(*) filter (where ${jobMatches.status} = 'pending')::int`,
196→        approved: sql<number>`count(*) filter (where ${jobMatches.status} = 'approved')::int`,
197→        rejected: sql<number>`count(*) filter (where ${jobMatches.status} = 'rejected')::int`,
198→      })
199→      .from(jobMatches)
200→      .where(scopeCondition),
